INSERT INTO public.problem_statements
  (slug, title, description, how_to_start, domain, difficulty, organisation,
   source, source_event, official_url, dataset_links, resource_links, tags)
VALUES
  ('sih-women-safety-analytics-cctv', 'Women Safety Analytics — Protecting Women from Safety Threats', 'Build a video analytics system that monitors public-space CCTV feeds to flag situations that pose elevated risk to women — for instance a lone woman surrounded at night, or unusual crowd gestures. The output is a real-time alert stream for control rooms so officers can intervene before an incident escalates.', 'Start with a Python pipeline that wraps YOLOv8 for person detection and a pose model like MediaPipe or MMPose for gesture cues, fed by OpenCV from RTSP streams. The first concrete milestone is gender classification plus crowd-around-individual heuristics — count male and female detections in a sliding window, flag when a single woman is encircled at low light hours. Use the AVA-Kinetics or UCF-Crime dataset to bootstrap action recognition for shouting, chasing, or grabbing.

Next add a hotspot map by aggregating alert geometries to a Folium dashboard, and an SOS gesture detector trained on the WLASL or a custom dataset. Run inference on a Jetson Nano or any RTX laptop with TensorRT to keep latency under 200 ms per frame.

For evaluation, simulate scenarios using freely available street CCTV footage and measure false-positive rate per camera-hour — judges weigh that more than raw accuracy.', 'AI/ML', 'advanced', 'Bharat Electronics Limited (BEL)', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"UCF-Crime anomaly video dataset","url":"https://www.crcv.ucf.edu/projects/real-world/","format":"images"}]'::jsonb, '[{"label":"YOLOv8 docs","url":"https://docs.ultralytics.com/","kind":"docs"},{"label":"MediaPipe Pose","url":"https://developers.google.com/mediapipe/solutions/vision/pose_landmarker","kind":"docs"}]'::jsonb, ARRAY['computer-vision','cctv','safety','yolo','pose-estimation']::text[]),
  ('sih-conversational-image-chatbot-bel', 'Conversational Image Recognition Chatbot for Component Support', 'Engineers and technicians often need to identify electronic components in the field. Build a chatbot that accepts a photo of a component, identifies it, then answers follow-up questions in natural language about pinouts, ratings, and known failure modes.', 'The architecture splits into a vision head and a language head. For vision, fine-tune YOLOv8 or a lightweight CLIP variant on labelled images of common components — capacitors, BJTs, ICs, connectors. You can bootstrap labels using the open-source PCB component datasets on Roboflow Universe and add manually photographed parts.

For the language side, route detected component identifiers into a Llama 3.1 or Mistral 7B prompt with a retrieval layer over component datasheets (use LangChain plus a FAISS index over PDF datasheets pulled from manufacturer sites). The chatbot maintains a session so follow-up questions like what does pin 7 do reference the previously identified part.

Ship it as a Flask or FastAPI service with a simple React frontend. First end-to-end milestone — upload an image of an LM358 op-amp, get back the part number and a working answer to where is Vcc.', 'AI/ML', 'advanced', 'Bharat Electronics Limited (BEL)', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Reference open-source attempt","url":"https://github.com/soumyyy/SIH-BEL","kind":"repo"},{"label":"LangChain RAG tutorial","url":"https://python.langchain.com/docs/tutorials/rag/","kind":"tutorial"}]'::jsonb, ARRAY['chatbot','computer-vision','rag','llm','yolo']::text[]),
  ('sih-virtual-herbal-garden-ayush', 'Virtual Herbal Garden for AYUSH Medicinal Plants', 'Showcase the medicinal plants used in Ayurveda, Yoga, Unani, Siddha and Homeopathy as an immersive web platform. Students and curious users should be able to walk around a 3D garden, click on a plant, and read about its botanical name, dosage, region, and traditional uses.', 'Pick Three.js or react-three-fiber for the 3D scene — use a low-poly garden ground tile and load each plant as a glTF model. Source CC-licensed plant models from Sketchfab or use Blender to produce a handful of hero plants like tulsi, brahmi, ashwagandha, neem. Plant data — Latin name, family, parts used, dosha effects — can be scraped from the official NMPB e-Charak portal and the AYUSH e-book PDFs.

Layer on click-to-inspect cards with a side drawer, audio narration in Hindi and English using the Web Speech API, and quiz mode for school groups. Store plant metadata as JSON; do not over-engineer with a database for a hackathon prototype.

Deploy as a static Vite build on Netlify or Vercel. Make the bundle work on a mid-range Android phone — target under 4 MB initial JS payload and use draco compression on the glTF.', 'Education', 'intermediate', 'Ministry of AYUSH', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"e-Charak medicinal plants portal","url":"https://echarak.in/echarak/","format":"api"}]'::jsonb, '[{"label":"react-three-fiber docs","url":"https://docs.pmnd.rs/react-three-fiber/getting-started/introduction","kind":"docs"}]'::jsonb, ARRAY['three-js','ayush','education','3d-web','herbal']::text[]),
  ('sih-rescue-coordination-app', 'Rescue Agency Coordination Application for Disaster Response', 'During floods, earthquakes or industrial accidents, several agencies — NDRF, fire, police, civil hospitals — show up but communicate over WhatsApp groups and walkie-talkies. Build a unified mobile and web app that lets each agency post their position, available assets, and pending tasks so a single commander view stays current.', 'Use Flutter or React Native for the field app and a Next.js dashboard for the commander. Realtime sync is the hard bit — set up Supabase Realtime or a Socket.IO server on a small node — and ensure low-bandwidth degradation by sending only deltas. Authentication should distinguish agency roles so a fire officer cannot reassign a medical team.

The map view is the soul of the product. Use MapLibre GL with OpenStreetMap tiles for offline-capability — pre-cache tiles for likely disaster zones. Tasks are pinned to coordinates and carry a status pill — open, claimed, done. A short audio note attachment is more useful in the field than a typed paragraph.

For the first build, simulate three agencies with three logged-in test accounts and a fake incident polygon. Score yourself on time-from-incident-pin to first-agency-claim — judges look for that responsiveness number.', 'Govt', 'intermediate', 'Ministry of Home Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"MapLibre GL JS","url":"https://maplibre.org/maplibre-gl-js/docs/","kind":"docs"},{"label":"Supabase Realtime","url":"https://supabase.com/docs/guides/realtime","kind":"docs"}]'::jsonb, ARRAY['disaster','realtime','maps','flutter','coordination']::text[]),
  ('sih-borewell-rescue-robot', 'Borewell Rescue Robotics Device', 'Children sometimes fall into abandoned uncapped borewells and rescues take hours of risky digging. Design a slim robotic device that can descend a narrow borewell, locate the child, secure them, and assist in extraction with cameras and a manipulator.', 'This is a hardware build. Start with a modular tube around 200 mm diameter built from PVC pipe sections joined by 3D-printed couplings. Inside, mount a 360-degree micro camera with IR illumination, a downward LIDAR or ultrasonic for distance, and an inflatable airbag harness made from rip-stop nylon that deploys below the child to support body weight.

For control, use an ESP32 with a long Cat-6 tether for both power and data — wireless dies at depth. Stream camera to a laptop using FFmpeg over UDP and let an operator drive the harness inflation manually. Sensors should include CO2 and oxygen because borewell air is often deadly.

First prototype milestone — lower the device into a 6 m vertical PVC test rig in a college lab, identify a doll, and successfully inflate the harness underneath it. Document the lateral force the harness can support — that is the metric judges fixate on.', 'IoT', 'advanced', 'Ministry of Home Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"ESP32 video streaming guide","url":"https://randomnerdtutorials.com/esp32-cam-video-streaming-web-server-camera-home-assistant/","kind":"tutorial"}]'::jsonb, ARRAY['robotics','rescue','embedded','esp32','disaster']::text[]),
  ('sih-phishing-domain-detection', 'Phishing Domain Detection Using AI/ML', 'Threat hunters today look at suspicious URLs by hand. Build a model that takes a domain — or a freshly registered one from a Certificate Transparency feed — and predicts whether it is a phishing site impersonating a bank, government portal, or popular brand.', 'Feature engineering is more valuable than a fancy model here. Pull a labelled corpus from PhishTank and OpenPhish for positives and the Tranco top-1M for negatives. Compute features per domain — length, hyphen count, digit ratio, Levenshtein distance to top brands, TLD risk, age in days from WHOIS, MX record presence, presence of suspicious tokens like login, verify, secure.

Train a gradient-boosting model — LightGBM is the sweet spot for tabular features at this scale — and add a sequence model like a 1D CNN over character embeddings that captures look-alike domains such as paypa1.com. Hook the trained pipeline to a Certstream WebSocket so newly issued TLS certificates feed through it live, surfacing high-risk domains to a tiny React dashboard.

The demo that wins this kind of problem is one that catches a brand-impersonation domain registered in the last ten minutes that real threat feeds have not yet flagged. Show that on stage.', 'AI/ML', 'intermediate', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"PhishTank verified phishing URLs","url":"https://phishtank.org/","format":"csv"},{"label":"Tranco top sites list","url":"https://tranco-list.eu/","format":"csv"}]'::jsonb, '[{"label":"Certstream live CT feed","url":"https://certstream.calidog.io/","kind":"docs"}]'::jsonb, ARRAY['phishing','cybersecurity','ml','lightgbm','ct-logs']::text[]),
  ('sih-ransomware-readiness-tool', 'Ransomware Readiness Assessment Tool', 'Most public-sector IT teams discover gaps in their ransomware posture only after they get hit. Build a tool that scans a Windows or Linux environment, checks dozens of hardening signals, and produces a posture score with prioritized fixes.', 'Treat this as an auditor in a box. Use PowerShell for Windows checks and Bash for Linux. The check catalogue should map to MITRE ATT&CK initial-access and impact tactics — patch level, RDP exposed to the internet, SMBv1 enabled, admin account count, Volume Shadow Copy retention, Microsoft Defender tamper protection, backup last-success age, macro policy, LAPS deployed.

Wrap the checks in a Python orchestrator that runs them over WinRM or SSH for a target host list, collects JSON results, and feeds a scoring engine. The output is an HTML report with a 0 to 100 score and a CSV remediation backlog ordered by exploitability.

For the demo, target a deliberately weakened Windows 10 VM and a hardened one, and show the score gap. Reference CIS Benchmarks for thresholds so you can defend every score decision.', 'AI/ML', 'intermediate', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"MITRE ATT&CK matrix","url":"https://attack.mitre.org/","kind":"docs"},{"label":"CIS Benchmarks","url":"https://www.cisecurity.org/cis-benchmarks","kind":"docs"}]'::jsonb, ARRAY['cybersecurity','ransomware','powershell','audit','hardening']::text[]),
  ('sih-sbom-generator-offline', 'Software Bill of Materials Generator for Offline Networks', 'Air-gapped government networks cannot run cloud-based SBOM tools. Build a self-contained CLI that walks a source tree or a binary, identifies every third-party dependency including transitive ones, and emits an SBOM in CycloneDX and SPDX formats.', 'Wrap several open-source detectors. Use Syft to scan container images and binaries, npm ls and pip-tools to recover deep transitive trees, and a regex pass over Maven, Gradle, go.mod and Cargo.toml. Normalise everything into the CycloneDX 1.5 JSON schema so the output stays interoperable.

Now add the offline twist. Bundle a snapshot of the OSV vulnerability database and the deps.dev metadata into a SQLite file so the tool can mark known-vulnerable components without internet. Update mechanism is a signed tarball dropped on a USB stick.

Ship as a single static binary using Go or as a PyInstaller bundle. Demo it by scanning a deliberately vintage open-source project — older versions of Log4j, jQuery, lodash — and showing the CVE list it produces without ever phoning home.', 'Web', 'intermediate', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"OSV vulnerability dataset","url":"https://osv.dev/","format":"json"}]'::jsonb, '[{"label":"CycloneDX spec","url":"https://cyclonedx.org/specification/overview/","kind":"docs"},{"label":"Syft","url":"https://github.com/anchore/syft","kind":"repo"}]'::jsonb, ARRAY['sbom','supply-chain','security','offline','cli']::text[]),
  ('sih-tor-hidden-server-enum', 'TOR Hidden Server Enumeration and Surface Mapping', 'Investigators need to map relationships between onion services — which ones share TLS certificates, server banners, or analytics IDs. Build a tool that crawls a seed list of hidden services and produces a graph of connections without de-anonymising users.', 'Set up a controlled Tor client using Stem in Python so you can route HTTP requests through SocksiPy and rotate circuits. Crawl from a seed list — Ahmia, the Hunchly directory — and harvest TLS certs, HTML fingerprints, favicon hashes, Google Analytics and AdSense IDs.

Store each onion as a node and create edges when two onions share a non-trivial fingerprint — same Bitcoin address in HTML, same favicon md5, same SSH banner on a non-standard port. Use Neo4j or NetworkX plus Cytoscape.js for the visual front-end.

Ethics matters — the tool must collect only public-facing metadata, never attempt to deanonymise. Demo on a snapshot of harmless marketplace and forum onions, and show clusters of probably-same-operator services.', 'AI/ML', 'advanced', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Stem Tor controller library","url":"https://stem.torproject.org/","kind":"docs"}]'::jsonb, ARRAY['tor','osint','graph','cybersecurity','neo4j']::text[]),
  ('sih-explainable-ai-rainfall', 'Explainable AI for Heavy Rainfall Event Prediction', 'Indian summer monsoon brings cloudbursts that flash-flood Himalayan valleys with hours of warning at best. Build a model that predicts heavy rainfall events from satellite imagery and reanalysis data, and crucially explains which atmospheric features drove each prediction.', 'Pull INSAT-3D imagery from MOSDAC for the cloud feature set and ERA5 reanalysis for surface variables — humidity, CAPE, wind shear. Build a ConvLSTM or a small transformer with a four-hour look-back of stacked channels, predicting a binary heavy-rain label per 25 km grid cell six hours ahead.

The explainability piece is the discriminator at SIH. Bolt on Integrated Gradients or Grad-CAM to highlight which channel — convective available potential energy, mid-level humidity, infrared cloud-top — pushed the model toward a positive prediction. Render those as a side-by-side animation with the actual rainfall observation from IMD gridded data.

For evaluation, use POD, FAR and CSI scores on a held-out monsoon season. Beat persistence baselines by a clear margin and your demo writes itself.', 'AI/ML', 'advanced', 'ISRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"MOSDAC INSAT data portal","url":"https://mosdac.gov.in/","format":"api"},{"label":"ERA5 reanalysis","url":"https://cds.climate.copernicus.eu/","format":"api"}]'::jsonb, '[{"label":"Captum explainability library","url":"https://captum.ai/","kind":"docs"}]'::jsonb, ARRAY['weather','xai','satellite','convlstm','isro']::text[]),
  ('sih-quantum-secure-email', 'Quantum-Secure Email Client Application', 'Once quantum computers become practical, today''s RSA and ECC encryption protecting email will fall. Build an email client that uses post-quantum cryptography for key exchange and signatures while remaining interoperable with regular IMAP and SMTP servers.', 'Use the Open Quantum Safe project''s liboqs which provides reference implementations of NIST-finalist algorithms like Kyber for KEM and Dilithium for signatures. Bind them into a Python or Rust client — Rust is the safer choice given crypto code — by linking against the oqs C library through bindings.

The email flow becomes — sender fetches the recipient public Kyber key from a directory you stand up, encapsulates a shared secret, AES-GCM encrypts the message body, signs with Dilithium, and packages everything as a single MIME attachment. The recipient client reverses it. Interoperability requires the message remain valid RFC 5322 so existing servers do not reject it.

Demo by sending a quantum-secure email between two laptops via a public Gmail account — the body Gmail sees is just an opaque attachment. Bonus points for a hybrid mode that pairs PQ with X25519 so you stay safe even if one scheme falls.', 'AI/ML', 'advanced', 'ISRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Open Quantum Safe liboqs","url":"https://openquantumsafe.org/liboqs/","kind":"docs"},{"label":"NIST PQC project","url":"https://csrc.nist.gov/projects/post-quantum-cryptography","kind":"docs"}]'::jsonb, ARRAY['post-quantum','cryptography','email','kyber','dilithium']::text[]),
  ('sih-sar-change-detection', 'SAR Change Detection in Satellite Imagery', 'Synthetic Aperture Radar penetrates cloud and sees at night, making it ideal for tracking illegal construction, deforestation, or troop movement. Build a pipeline that takes two SAR scenes of the same area at different times and produces a clean change map.', 'Sentinel-1 SAR scenes are free on the Copernicus Data Space Ecosystem and ASF Vertex. Co-register two passes using SNAP or sarpy in Python, apply Lee speckle filtering, and convert to dB. The naive approach — log-ratio differencing — is your baseline. Improve it with a Siamese U-Net trained on the OSCD or LEVIR-CD datasets adapted to SAR.

The data engineering matters here. SAR scenes are huge — patch them into 256-by-256 tiles, normalise per scene, handle the speckle noise during augmentation. Output a binary change mask plus a confidence raster.

Wrap the model behind a small FastAPI service. The demo is dropping in two scene IDs over a known illegal-mining or deforestation site like Aravalli quarries or Hasdeo Arand, and showing the highlighted polygons against an OpenStreetMap basemap.', 'AI/ML', 'advanced', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"Copernicus Sentinel-1 portal","url":"https://dataspace.copernicus.eu/","format":"api"},{"label":"ASF SAR data search","url":"https://search.asf.alaska.edu/","format":"api"}]'::jsonb, '[{"label":"SNAP toolbox","url":"https://step.esa.int/main/toolboxes/snap/","kind":"docs"}]'::jsonb, ARRAY['sar','remote-sensing','change-detection','deep-learning','geospatial']::text[]),
  ('sih-ganga-water-quality-dss', 'Real-time Ganga River Water Quality Forecasting DSS', 'The Namami Gange programme needs early warning when industrial discharge or sewage pushes a Ganga stretch over pollution thresholds. Build a decision support system that ingests IoT sensor readings, satellite imagery and weather data to forecast water quality 24 to 72 hours ahead.', 'Start with the open CPCB river data portal which publishes BOD, DO, pH and turbidity at known stations. Pull historical series, align with rainfall from IMD and satellite-derived turbidity proxies from Sentinel-2 using the NDTI band combination. Build a multivariate LSTM or Temporal Fusion Transformer that predicts each parameter per station 24, 48, 72 hours out.

Wrap predictions in a Mapbox or MapLibre dashboard that draws the Ganga river polyline coloured by predicted DO level, with click-to-inspect stations. Add a rule engine that emits an alert when forecast DO drops below 4 mg per litre — the fish-survival threshold.

IoT integration is the polish — show one demo sensor node built with an ESP32 plus a DFRobot pH probe streaming to your backend through MQTT. The judge experience is to see a current reading flow in and the next-day forecast update in front of them.', 'IoT', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"CPCB water quality portal","url":"https://cpcb.nic.in/real-time-water-quality-data/","format":"api"}]'::jsonb, '[{"label":"Temporal Fusion Transformer","url":"https://pytorch-forecasting.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['water-quality','iot','forecasting','ganga','dss']::text[]),
  ('sih-groundwater-level-predictor', 'Ground Water Level Predictor', 'Farmers and district authorities need to know whether the watertable under their land will fall below pump reach this season. Build a software application that predicts groundwater levels for any village in India using historical DWLR readings, rainfall, and land-use signals.', 'The Central Ground Water Board publishes Digital Water Level Recorder data at thousands of wells. Pull it via India-WRIS API along with IMD gridded rainfall and the cropping-pattern shapefiles from Bhuvan. The basic model is a per-well ARIMAX or Prophet with rainfall as an exogenous regressor. The better model is a graph neural network where wells are nodes connected by aquifer adjacency.

For the UI, a citizen should be able to type a village name and get a 6-month groundwater forecast with an uncertainty band. Block officials need a different view that prioritises which villages will likely fall below critical depth so they can plan recharge structures.

First milestone — pick one over-exploited block like a part of Bundelkhand or Marathwada, get five years of historical DWLR, predict next month and validate against held-out readings. Real numbers from a real block beat any flashy UI in pitch round.', 'AI/ML', 'intermediate', 'Ministry of Jal Shakti', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"India-WRIS groundwater portal","url":"https://indiawris.gov.in/wris/","format":"api"}]'::jsonb, '[{"label":"Prophet forecasting","url":"https://facebook.github.io/prophet/","kind":"docs"}]'::jsonb, ARRAY['groundwater','forecasting','agriculture','india-wris','time-series']::text[]),
  ('sih-groundwater-chatbot', 'AI Chatbot for Groundwater Information Dissemination', 'Citizens, journalists and panchayat officials want plain answers about local aquifers — current depth, recharge zones, contamination — but the data is spread across PDFs and dashboards. Build a chatbot that answers in English, Hindi and regional languages by querying authoritative groundwater datasets.', 'Build a retrieval-augmented generation pipeline. Ingest CGWB annual reports, India-WRIS API responses, and state groundwater atlases into a vector store like Chroma or pgvector. Use BGE or IndicBERT embeddings — generic OpenAI embeddings underperform on Indian place names and technical terms.

The LLM is the answering layer. For Indian-language fluency consider AI4Bharat Airavata, IndicTrans2 for translation, or a Llama 3.1 with a small Hindi finetune. Always cite the source document and refuse to answer when retrieval confidence is low — overconfident hallucinations are the failure mode judges hammer.

Deploy as a WhatsApp bot using the Meta Cloud API so it meets villagers where they already are. Demo with three questions in three languages — one about groundwater depth in a specific Telangana mandal, one about safe arsenic limits, one about how to claim a recharge scheme subsidy.', 'AI/ML', 'intermediate', 'Ministry of Jal Shakti', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"AI4Bharat Airavata","url":"https://ai4bharat.iitm.ac.in/airavata/","kind":"docs"},{"label":"WhatsApp Cloud API","url":"https://developers.facebook.com/docs/whatsapp/cloud-api/","kind":"docs"}]'::jsonb, ARRAY['chatbot','rag','groundwater','indic-nlp','whatsapp']::text[]),
  ('sih-construction-waste-management', 'Construction and Demolition Waste Management Platform', 'Indian cities generate huge quantities of brick rubble and concrete debris that ends up dumped on roadsides. Build a platform that matches generators of C and D waste — builders, demolition contractors — with authorised recyclers and tracks each truckload from source to processing.', 'Frame it as a three-sided marketplace — generator, transporter, recycler — with a municipal observer role. Use Next.js for the web app and Flutter for the driver app. The unit of work is a manifest — kilograms, type of waste, source GPS, destination GPS, transporter vehicle number — that gets digitally signed at pickup and drop.

Proof-of-delivery uses photo capture with EXIF GPS plus a QR code on the recycler weighbridge. Issue blockchain-anchored hashes only if you want — a simple append-only Postgres ledger with daily merkle root anchored to a public chain is cheaper and good enough. The municipal dashboard rolls up tonnes processed per ward and flags trucks that go off-route.

First end-to-end test — log a demolition site in one corner of your campus, create a manifest, drive a friend with the app to another corner posing as the recycler, and confirm the trip closed cleanly with the metadata judge expects.', 'Govt', 'intermediate', 'Ministry of Housing and Urban Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Swachh Bharat Mission C&D waste guidelines","url":"https://sbmurban.org/","kind":"docs"}]'::jsonb, ARRAY['waste','marketplace','logistics','smart-city','manifest']::text[]),
  ('sih-street-parking-management', 'Smart Real-time Street Parking Management', 'On-street parking in Indian cities is chaotic — drivers circle for slots while wardens issue tickets reactively. Build a system that detects occupancy of street parking bays in real time and exposes that to drivers and city authorities through a mobile app and dashboard.', 'Two viable sensing routes. Option A is computer vision — mount a few cameras on lamp posts and run a YOLOv8 or a fine-tuned RT-DETR model that detects each painted bay and reports its occupancy. Option B is ground sensors — magnetometer-based units that wake on vehicle arrival and report over LoRaWAN. For a hackathon, vision is cheaper to demo.

On the app side, build with Flutter and show a live map of bays coloured green or red. Allow advance reservation with payment via UPI Intent Deep-link so the user does not leave their parking flow. The warden side gets a heatmap of long-overstay violations.

For your demo, pick a single street near your campus, set up a webcam covering five painted bays, and run inference on a laptop. Stream to Supabase Realtime and watch your mobile app update as friends park and leave. That live loop is what wins.', 'IoT', 'intermediate', 'Ministry of Housing and Urban Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"YOLOv8 docs","url":"https://docs.ultralytics.com/","kind":"docs"}]'::jsonb, ARRAY['parking','smart-city','computer-vision','iot','flutter']::text[]),
  ('sih-street-light-fault-detection', 'Street Light Fault Detection System', 'Municipal staff currently learn that a street light is dead only when citizens complain. Build a system that automatically detects and reports faulty street lights — burnt-out, flickering, day-time burning — across a city without depending on citizen reports.', 'Two complementary signals. First, smart pole controllers that report current draw to a central platform over NB-IoT — burnt lamps draw close to zero, flickering ones oscillate. Use an ESP32 plus a non-invasive current sensor like the SCT-013 clamp; that fits inside the existing pole junction box.

Second, drive-by image capture using a dashcam on a municipal sweeper truck — run inference on a Jetson Orin Nano with YOLOv8 trained on photos of working, unlit, and broken lamp heads. Geotag each detection and reconcile with the controller data.

The platform is a Django or NestJS backend, MQTT broker, and a React dashboard with map view and a ticketing pipeline that pushes work orders to the electrical contractor. Demo on a small physical setup of three lamp boards, kill one, and watch a ticket appear in under a minute.', 'IoT', 'intermediate', 'Ministry of Housing and Urban Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"MQTT primer","url":"https://mqtt.org/","kind":"docs"}]'::jsonb, ARRAY['smart-city','iot','esp32','computer-vision','maintenance']::text[]),
  ('sih-grievance-ai-routing', 'AI-Based Grievance Lodging and Tracking', 'Citizen grievance portals like CPGRAMS receive lakhs of complaints and humans hand-route them to departments. Build an AI engine that ingests free-text grievances in multiple Indian languages, categorises them, identifies the correct department, deduplicates near-duplicates, and tracks SLA compliance.', 'The corpus to learn from is the closed-grievance archive published periodically by DARPG and individual ministry sites. If you cannot get raw data, scrape redressal-of-the-week posts to bootstrap labels. Train a multilingual classifier using MuRIL or XLM-R fine-tuned on grievance-to-department pairs. For Indic transliteration handling, run AI4Bharat IndicXlit upstream so Hinglish queries normalise to one script.

Add a near-duplicate detector — embed each grievance with sentence-transformers and use an HNSW index to fold incoming complaints into existing clusters. That immediately reduces officer workload because they handle a cluster, not a thousand individual tickets.

The dashboard view shows clusters sorted by size and SLA risk. Demo by typing five paraphrased complaints about a single pothole and watching them collapse into one ticket with five citizen IDs attached.', 'AI/ML', 'intermediate', 'Ministry of Housing and Urban Affairs', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"AI4Bharat IndicXlit","url":"https://ai4bharat.iitm.ac.in/indic-xlit","kind":"docs"},{"label":"sentence-transformers","url":"https://www.sbert.net/","kind":"docs"}]'::jsonb, ARRAY['nlp','grievance','egovernance','multilingual','clustering']::text[]),
  ('sih-adaptive-learning-parakh', 'AI-Driven Adaptive Learning Platform for PARAKH', 'School learners progress at different paces but most national assessment platforms serve the same set of questions to everyone. Build an adaptive engine for PARAKH that personalises question difficulty, identifies concept gaps and recommends targeted micro-lessons.', 'Model each learner with a knowledge-tracing approach. Implement Deep Knowledge Tracing or the more interpretable Bayesian Knowledge Tracing as your baseline, then iterate to a SAKT or AKT transformer. Train on the open ASSISTments and EdNet datasets to validate the pipeline before fine-tuning on Indian NCERT chapter tags.

For the front-end, build a React quiz UI that gates the next question on posterior mastery probability — easy questions early, harder ones as confidence rises, remediation tiles when posterior drops on a sub-skill. Pair each diagnosed gap with a 90-second NCERT or DIKSHA video.

Demo by walking a judge through two simulated students — one consistently strong, one struggling on fractions — and showing how the two diverging question paths emerge. Show a one-page learner report a teacher could print.', 'Education', 'advanced', 'AICTE', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"ASSISTments knowledge tracing data","url":"https://sites.google.com/site/assistmentsdata/","format":"csv"}]'::jsonb, '[{"label":"DIKSHA content platform","url":"https://diksha.gov.in/","kind":"docs"}]'::jsonb, ARRAY['edtech','knowledge-tracing','adaptive-learning','ncert','parakh']::text[]),
  ('sih-hyperspectral-anomaly-detection', 'Hyperspectral Image Anomaly Detection', 'Hyperspectral sensors capture hundreds of narrow bands per pixel, exposing materials invisible to the human eye — buried metal, camouflage, or chemical spills. Build a detector that, given a hyperspectral scene, highlights pixels that do not match local background spectra.', 'Begin with the classic Reed-Xiaoli detector as the baseline because every paper compares to it. Then implement a deep one-class autoencoder approach trained on background patches — anomalies show up as high reconstruction error. The AVIRIS and HyMap public scenes plus the Salinas and Indian Pines benchmarks give you labelled targets for evaluation.

Mind the dimensionality. PCA or MNF to reduce 200-plus bands to 30-50 before training, and use stride-aware patch extraction since hyperspectral scenes are small but rich. Use spectral angle mapper as an interpretable side metric.

Wrap it in a small viewer — Bokeh or Streamlit works — that lets a judge load a scene, paint a region as background, and see anomaly heatmaps overlaid. The most persuasive demo is a hidden vehicle in a desert AVIRIS scene popping out of an otherwise empty image.', 'AI/ML', 'advanced', 'NTRO', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"Indian Pines hyperspectral dataset","url":"https://www.ehu.eus/ccwintco/index.php/Hyperspectral_Remote_Sensing_Scenes","format":"images"}]'::jsonb, '[{"label":"Spectral Python library","url":"https://www.spectralpython.net/","kind":"docs"}]'::jsonb, ARRAY['hyperspectral','anomaly-detection','remote-sensing','autoencoder','defence']::text[]),
  ('sih-belt-conveyor-dislodgement', 'Belt Conveyor Dislodgement Prediction in Mines', 'Long belt conveyors at coal and iron ore mines suffer sudden belt slippage or tearing that halts production for days. Build a system that ingests vibration, current and thermal data from conveyor drives and predicts dislodgement events before they happen.', 'Instrument a single drive with a MEMS accelerometer like the ADXL355, a CT clamp for motor current, and an MLX90640 thermal camera looking at the head pulley. Stream samples at 1 kHz to an industrial PC over Modbus or MQTT. The first analytics layer is FFT-based — vibration spectra shift recognisable amounts before a belt mistracks.

For the prediction model, label historical events from the maintenance logs of a partner mine — if you cannot get real logs, simulate with a small belt rig and induce mistracking by shifting the head pulley. Train an LSTM autoencoder on healthy windows and use reconstruction error as the risk score, with thresholds calibrated to maintenance lead time.

The operator dashboard is a Grafana board with a single rolling gauge per drive plus a 24-hour drift trend. Show two demo states — green for healthy, amber for predicted slip in two hours — so judges read the value at a glance.', 'IoT', 'advanced', 'Ministry of Mines', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Modbus protocol primer","url":"https://modbus.org/specs.php","kind":"docs"}]'::jsonb, ARRAY['predictive-maintenance','mining','iot','vibration','lstm']::text[]),
  ('sih-non-electrical-solar-tracker', 'Non-Electrical Solar Panel Tracking Device', 'Single-axis solar trackers usually need motors, batteries and electronics that themselves consume part of the gain. Design a tracking mechanism that follows the sun without any electrical actuation — purely mechanical or thermo-mechanical.', 'Look into bimetallic-strip or shape-memory-alloy actuators driven by differential sun exposure. A classic design uses two refrigerant-filled copper canisters mounted on opposite sides of the panel — the canister facing the sun heats faster, its refrigerant vaporises, the pressure difference rotates the panel until both canisters see equal sun, achieving passive tracking.

Protoype with CPVC pipe sections sealed with R134a or even isopropanol for safer experimentation, a counterweight balance arm, and a hardwood frame supporting a 10 W solar panel. Add a friction damper to prevent oscillation. Measure tracking accuracy with a tilt sensor logging position once a minute.

For the demo, run side-by-side comparison — fixed panel versus your passive tracker — and report kWh harvested over a clear-sky day. A 15 to 20 percent uplift over fixed is a believable, defensible number to put on stage.', 'Agriculture', 'advanced', 'Department of Science and Technology', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"Passive solar tracking concept","url":"https://en.wikipedia.org/wiki/Solar_tracker","kind":"docs"}]'::jsonb, ARRAY['solar','passive-tracking','mechanical','renewable','hardware']::text[]),
  ('sih-smart-yoga-mat-ai', 'Smart Yoga Mat with AI Posture Correction', 'Self-taught yoga practitioners get postures subtly wrong and hurt themselves over months. Design a smart yoga mat with embedded pressure sensors plus a companion app that detects asana, scores posture, and gives spoken corrections in real time.', 'The mat is a grid of force-sensitive resistor pads — 6 by 12 cells is enough — multiplexed through an ESP32 with two CD74HC4067 analog mux ICs. The mat publishes a pressure frame at 10 Hz to a phone over BLE. On the phone, run a MediaPipe Pose stream from the front camera plus the pressure frame as a second modality.

Train an asana classifier on the public Yoga-82 dataset for the visual side, then layer the pressure pattern as an extra feature so weight-balance asanas like Vrikshasana get correctly scored. Posture scoring becomes a per-joint angle comparison against the canonical asana, with audio cues like lift your left knee higher generated through Bhashini TTS.

First working demo — three asanas, live scoring, audio correction, and a session summary card. That is enough to win the round; productisation can wait.', 'IoT', 'advanced', 'Ministry of AYUSH', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[{"label":"Yoga-82 asana dataset","url":"https://sites.google.com/view/yoga-82/home","format":"images"}]'::jsonb, '[{"label":"Bhashini Indic TTS","url":"https://bhashini.gov.in/","kind":"docs"},{"label":"MediaPipe Pose","url":"https://developers.google.com/mediapipe/solutions/vision/pose_landmarker","kind":"docs"}]'::jsonb, ARRAY['yoga','iot','pose-estimation','wearable','ayush']::text[]),
  ('sih-drone-evapotranspiration', 'Drone-Based Evapotranspiration Sensing for Water Accounting', 'Accurate water accounting in basins requires per-field evapotranspiration estimates, which satellite passes give too coarsely. Build a drone-borne sensing payload plus a processing pipeline that produces high-resolution ET maps over agricultural plots.', 'ET requires thermal plus multispectral data. Mount a FLIR Lepton or a Vue Pro R thermal sensor alongside a MicaSense RedEdge multispectral camera on a DJI M300 or a custom hexacopter. Plan flights at solar noon for stable thermal signatures and target sub-1 metre GSD.

On the ground, use the METRIC or SEBAL energy-balance model implemented in Python with rasterio and PyMETRIC or its modern fork. Inputs are surface temperature from thermal, NDVI from multispectral, albedo, and weather-station readings of net radiation, wind, humidity. Output is a per-pixel ET in mm per day.

For the demo, fly two adjacent fields — one well-watered, one stressed — and produce a side-by-side ET map showing the difference. The persuasive number is the percentage water saving a farmer would realise if they irrigated based on your map. Aim for a 20-percent figure or higher.', 'Agriculture', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"PyMETRIC reference repo","url":"https://github.com/usbr/PyMETRIC","kind":"repo"}]'::jsonb, ARRAY['drones','agriculture','evapotranspiration','remote-sensing','irrigation']::text[]),
  ('sih-myoelectric-prosthesis-low-cost', 'Cost-Effective Myoelectric Prosthesis', 'Imported myoelectric prosthetic hands cost lakhs and are out of reach for most Indian amputees. Design and build a low-cost myoelectric forearm prosthesis under a target price of 25,000 rupees that recognises at least four hand gestures.', 'The skeleton is a 3D-printed PLA forearm with tendon-driven fingers based on the open-source Brunel Hand or InMoov designs. Actuation is two or three micro servos pulling Dyneema cords; that keeps weight under 500 g.

Surface EMG sensing uses MyoWare 2.0 or a custom AD8232-based front-end taped on the residual limb. Sample at 1 kHz into a Teensy 4.0 or ESP32, extract features per 200-ms window — mean absolute value, zero crossings, Willison amplitude — and classify into open, close, pinch, point with a small SVM or random forest. The dataset is built by recording from the user themselves; calibration sessions of 15 minutes are common in literature.

Measure mass, grip force, recognition accuracy and battery life. A 3-hour battery, 200 g, 85 percent gesture accuracy under a 5,000 rupee bill of materials is judge-worthy. Document everything as an open-hardware kit so others can fabricate it.', 'Health', 'advanced', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2024', 'https://sih.gov.in/sih2024PS', '[]'::jsonb, '[{"label":"InMoov open-source hand","url":"https://inmoov.fr/","kind":"docs"},{"label":"MyoWare 2.0 EMG sensor","url":"https://myoware.com/","kind":"docs"}]'::jsonb, ARRAY['prosthetics','emg','accessibility','3d-printing','low-cost']::text[]),
  ('gsoc-postgres-jdbc-struct-array', 'PostgreSQL JDBC Struct and Array Support', 'Implement the createStruct() factory method in pgjdbc so JDBC users can map SQL structured types directly to Java Struct objects. The work touches type-mapping, value parsing and round-trip coverage in the pgjdbc test harness.', 'Clone pgjdbc/pgjdbc on GitHub and read the README plus CONTRIBUTING.md. Skim org.postgresql.jdbc.PgConnection — that is where createStruct currently lives unimplemented — and trace how PgArray already deserialises composite types in the binary protocol. The existing array tests under pgjdbc/src/test/java/org/postgresql/test/jdbc2/ArrayTest.java are the template for what a structured-type test should look like.

Spin up a local PostgreSQL 16+ with a CREATE TYPE point AS (x int, y int) example and write a failing test before any code. Lean on Maven (mvn -P release-artifacts verify) — pgjdbc has no exotic build setup. Introduce yourself on the pgsql-jdbc mailing list at lists.postgresql.org/mj/mj_wwwusr and link your patch to the relevant TODO entry once you have a draft.

Mentor contact happens through pgsql-jdbc and the wiki page. Skills you should be comfortable with: JDBC contract reading, Java generics, and the PostgreSQL wire protocol message format (StartupMessage, RowDescription, DataRow).', 'OpenSource', 'intermediate', 'PostgreSQL', 'GSoC', 'GSoC 2024', 'https://wiki.postgresql.org/wiki/GSoC_2024', '[]'::jsonb, '[{"label":"pgjdbc repository","url":"https://github.com/pgjdbc/pgjdbc","kind":"repo"},{"label":"PostgreSQL GSoC entry page","url":"https://wiki.postgresql.org/wiki/GSoC","kind":"docs"}]'::jsonb, ARRAY['java','jdbc','postgresql','databases','open-source']::text[]),
  ('gsoc-pgagroal-io-uring', 'pgagroal: Modern I/O Layer with epoll and io_uring', 'Replace pgagroal''s libev-based event loop with a thin abstraction over epoll and io_uring, so the connection pooler can push more PostgreSQL connections per second on Linux. Expect to redesign the dispatcher and rewrite socket lifecycle handling.', 'Start by reading pgagroal/pgagroal on GitHub — particularly src/libpgagroal/network.c and the worker loop in worker.c — and benchmark the current libev path with pgbench so you have a baseline. Read the io_uring man pages (io_uring_setup, io_uring_enter) and the liburing examples; the kernel docs at kernel.dk/io_uring.pdf are essential context.

The build is plain CMake. Open a draft PR early sketching an IoBackend interface with epoll and io_uring implementations behind it, and run pgagroal under perf and bpftrace to confirm syscall reduction. Talk to the maintainers on the pgagroal Discord (linked from the README) and on the pgsql-hackers list — mentor Jesper Pedersen is active in both.

You need solid C, an understanding of non-blocking sockets, and patience for tracing — most regressions show up only under saturating load. Plan for a 350-hour project and a multi-stage merge.', 'OpenSource', 'advanced', 'PostgreSQL', 'GSoC', 'GSoC 2024', 'https://wiki.postgresql.org/wiki/GSoC_2024', '[]'::jsonb, '[{"label":"pgagroal source","url":"https://github.com/agroal/pgagroal","kind":"repo"},{"label":"io_uring kernel paper","url":"https://kernel.dk/io_uring.pdf","kind":"docs"}]'::jsonb, ARRAY['c','linux','io-uring','networking','postgresql']::text[]),
  ('gsoc-postgres-abi-compliance-checker', 'PostgreSQL ABI Compliance Checker', 'Build an automated tool that hooks into the PostgreSQL CI pipeline, checks each commit for ABI compatibility, and surfaces an ABI compliance report similar to coverage.postgresql.org. The checker should alert maintainers whenever an incompatible ABI change lands.', 'Read the PostgreSQL build system (src/Makefile.global.in and meson.build) to understand which shared objects get produced. Get familiar with existing ABI tools — abi-dumper and abi-compliance-checker from lvc-tools are the obvious starting points — by running them locally against two adjacent minor releases of libpq and pg_query.

The deliverable is part scraper, part webapp: you will need to scaffold a small service that consumes buildfarm artifacts, runs the diff, and posts HTML reports. Mirror the layout of coverage.postgresql.org for consistency. Skills: C build system literacy, ELF/DWARF symbol handling, plus enough Python or shell to glue the pieces together.

Introduce yourself on pgsql-hackers with a short proposal and CC the assigned mentor. Most reviews happen on that list; the postgresql Slack #buildfarm channel is the second-line venue.', 'OpenSource', 'intermediate', 'PostgreSQL', 'GSoC', 'GSoC 2025', 'https://wiki.postgresql.org/wiki/GSoC_2025', '[]'::jsonb, '[{"label":"abi-compliance-checker","url":"https://github.com/lvc/abi-compliance-checker","kind":"repo"},{"label":"PostgreSQL developer FAQ","url":"https://wiki.postgresql.org/wiki/Developer_FAQ","kind":"docs"}]'::jsonb, ARRAY['c','postgresql','ci','abi','tooling']::text[]),
  ('gsoc-jenkins-cloudevents-plugin', 'Jenkins CloudEvents Plugin', 'Design a Jenkins plugin that can both emit and listen to CloudEvents and CDEvents, letting Jenkins instances participate in event-driven CI/CD pipelines alongside Tekton, Argo and similar systems. The plugin must speak the CDEvents schema and expose a Jenkins-friendly configuration UI.', 'Start with the Jenkins plugin tutorial at jenkins.io/doc/developer/plugin-development — it walks you through Maven archetypes, JCasC support and the Stapler web layer. Then read the CloudEvents Java SDK (cloudevents/sdk-java) and the CDEvents Go and Java SDKs to understand the schema you must emit.

Fork jenkinsci and bootstrap a hpi project. Wire up an HTTP sink first, then add NATS or Kafka transports behind the same interface. Use the existing notification-plugin and event-driven-pipeline plugins as references. Run mvn hpi:run to spin up a sandbox Jenkins with your plugin loaded.

Introduce yourself on the Jenkins Gitter channel jenkinsci/gsoc and the jenkinsci-dev mailing list — mentors Kris Stern and Bervianto Leo Pratama answer questions there. You should be comfortable with Java, Maven, and a working understanding of webhooks plus at least one event broker.', 'OpenSource', 'intermediate', 'Jenkins', 'GSoC', 'GSoC 2024', 'https://www.jenkins.io/projects/gsoc/2024/project-ideas/', '[]'::jsonb, '[{"label":"CloudEvents Java SDK","url":"https://github.com/cloudevents/sdk-java","kind":"repo"},{"label":"Jenkins plugin dev guide","url":"https://www.jenkins.io/doc/developer/plugin-development/","kind":"tutorial"}]'::jsonb, ARRAY['java','jenkins','cloudevents','ci-cd','plugins']::text[]),
  ('gsoc-jenkins-llm-domain-knowledge', 'Domain-Specific LLM Assistant for Jenkins', 'Build a local assistant that fine-tunes or augments an open-source LLM with Jenkins-specific documentation, plugin catalogues and Jenkinsfile patterns. The deliverable is a chat-style web app that helps users debug pipelines and discover plugins without leaving Jenkins.', 'Read the existing Jenkins documentation under jenkins-infra/jenkins.io — that corpus, plus the plugin index at plugins.jenkins.io, is your initial training and retrieval set. Pick a base model that runs locally via Ollama (Llama 3, Mistral or Gemma) and prototype a RAG loop using LangChain with FAISS or Chroma for the vector store.

The frontend is a React app that talks to a small Python FastAPI backend. Mirror the Jenkins UI palette so it can later embed as a plugin. Keep the model offline-first — the project is explicitly about local fine-tuning, not OpenAI calls. Run evaluations against a held-out set of real questions scraped from community.jenkins.io.

Introduce yourself on the jenkinsci-dev mailing list and the Jenkins AI working group on Gitter. Mentors Shivay Lamba and Harsh Pratap Singh are the LLM specialists; ping them with your retrieval-quality numbers early.', 'OpenSource', 'advanced', 'Jenkins', 'GSoC', 'GSoC 2024', 'https://www.jenkins.io/projects/gsoc/2024/project-ideas/', '[]'::jsonb, '[{"label":"LangChain docs","url":"https://python.langchain.com/docs/get_started/introduction","kind":"docs"},{"label":"Ollama","url":"https://ollama.com/","kind":"tutorial"}]'::jsonb, ARRAY['python','react','llm','rag','jenkins']::text[]),
  ('gsoc-kde-okular-pdf-javascript', 'Okular PDF Forms JavaScript Support', 'Expand Okular''s JavaScript engine so PDF forms — especially those from European governments and tax authorities — work as users expect. Today Okular implements only a small subset of the Acrobat JS object model and many real forms silently fail validation.', 'Clone invent.kde.org/graphics/okular and read core/script/ — that directory contains the QJSEngine-backed runtime and the JS object proxies that mirror the Acrobat API. Reproduce a failing form using one of the public Spanish or Italian tax PDFs the maintainers reference in their bug reports, then walk through the JS callbacks Okular fires to see exactly which method is missing.

The build is plain CMake with KDE Frameworks 6. Add objects field by field — AFNumber_Format, AFDate_Format, Field.setFocus — and write QTest cases that drive an in-memory document. Cross-check behaviour against the Adobe Acrobat JS reference and Poppler''s libpoppler-glib expectations.

Introduce yourself in the #okular Matrix room on kde.org and on okular-devel@kde.org. Mentor Albert Astals Cid reviews almost every patch personally — keep merge requests small. Required skills: C++, Qt, and willingness to read JavaScript-from-Acrobat dialect specs.', 'OpenSource', 'advanced', 'KDE', 'GSoC', 'GSoC 2024', 'https://community.kde.org/GSoC/2024/Ideas', '[]'::jsonb, '[{"label":"Okular repository","url":"https://invent.kde.org/graphics/okular","kind":"repo"},{"label":"KDE GSoC entry page","url":"https://community.kde.org/GSoC","kind":"docs"}]'::jsonb, ARRAY['cpp','qt','kde','pdf','javascript']::text[]),
  ('gsoc-kde-python-bindings-frameworks', 'Python Bindings for KDE Frameworks', 'Provide first-class Python bindings for selected KDE Frameworks modules so developers can build KDE apps with Qt for Python instead of C++. The work involves generating bindings with shiboken and shipping importable Python packages.', 'Read carl-schwan/kde-python-bindings prototype and the official Qt for Python tutorials at doc.qt.io/qtforpython-6. Get comfortable with shiboken6''s typesystem XML — that is the file you will edit for every framework you target (KCoreAddons, KI18n, KConfig are the right starting points).

Set up a KDE neon developer image so you have all the KF6 packages preinstalled, then add a Python module to one framework and confirm import kcoreaddons; KAboutData(...) works. Once the pattern is stable, script the bootstrap for the remaining frameworks. CMake''s PySide6 integration handles install paths.

Introduce yourself on the #kde-devel Matrix room and ping mentor Carl Schwan (@carl:kde.org). Strong C++ and a working knowledge of CPython''s reference counting model are essential — shiboken''s pitfalls almost always reduce to ownership errors.', 'OpenSource', 'intermediate', 'KDE', 'GSoC', 'GSoC 2024', 'https://community.kde.org/GSoC/2024/Ideas', '[]'::jsonb, '[{"label":"Qt for Python docs","url":"https://doc.qt.io/qtforpython-6/","kind":"docs"},{"label":"KDE Frameworks list","url":"https://api.kde.org/frameworks/","kind":"docs"}]'::jsonb, ARRAY['cpp','python','qt','kde','bindings']::text[]),
  ('gsoc-gnome-libipuz-rust-port', 'Port libipuz from C to Rust for GNOME Crosswords', 'Rewrite libipuz — the C library that loads and saves crossword puzzle files used by GNOME Crosswords — in Rust. The port should keep the existing C ABI through a thin shim so consumers can migrate incrementally.', 'Read the existing C sources at gitlab.gnome.org/jrb/libipuz; the parser for the .ipuz JSON format and the model for clues, cells and styles are where most of the logic lives. Sketch a Rust crate using serde_json for parsing and gobject-rs to expose the GObject types the GNOME world expects.

Keep the migration mechanical: lift one module at a time, build it as a static library, link it into the existing C library and let the test suite drive the cutover. The Crosswords editor itself lives at gitlab.gnome.org/jrb/crosswords and exercises virtually every public API — run it after each step.

Introduce yourself in #crosswords:gnome.org on Matrix and ping mentors Jonathan Blandford and Federico Mena Quintero. Required skills: Rust, C, and at least a passing familiarity with GObject and glib — gtk-rs already does the heavy lifting for the bindings.', 'OpenSource', 'intermediate', 'GNOME', 'GSoC', 'GSoC 2024', 'https://gsoc.gnome.org/2024/', '[]'::jsonb, '[{"label":"libipuz source","url":"https://gitlab.gnome.org/jrb/libipuz","kind":"repo"},{"label":"gtk-rs book","url":"https://gtk-rs.org/gtk4-rs/stable/latest/book/","kind":"tutorial"}]'::jsonb, ARRAY['rust','c','gnome','gobject','port']::text[]),
  ('gsoc-gnome-tracker-sparql-web-ide', 'Web IDE for Tracker SPARQL', 'Build a browser-based IDE for writing and debugging SPARQL queries against Tracker — GNOME''s RDF data store. The editor should provide schema-aware autocomplete, syntax highlighting and inline result tables so app developers can iterate quickly.', 'Read the Tracker docs at gnome.pages.gitlab.gnome.org/tracker and the libtracker-sparql introspection API — that GIR file is the schema source. Stand up a small backend that proxies SPARQL through libtracker-sparql via GObject Introspection (PyGObject is the path of least resistance) and exposes JSON to the browser.

For the frontend, fork CodeMirror 6 or Monaco and wire in a SPARQL grammar — there are existing community modes you can adapt. Schema-aware completion comes from querying the ontology directly: SELECT ?p WHERE { ?p a rdf:Property }. Render results as virtualised tables to handle large result sets.

Introduce yourself on #tracker:gnome.org on Matrix and the tracker-list mailing list. Mentors Carlos Garnacho and Sam Thursfield review there. Skills: HTML/JS, database theory, a dash of C/GObject when the wrapper layer leaks abstractions.', 'OpenSource', 'advanced', 'GNOME', 'GSoC', 'GSoC 2024', 'https://gsoc.gnome.org/2024/', '[]'::jsonb, '[{"label":"Tracker SPARQL docs","url":"https://gnome.pages.gitlab.gnome.org/tracker/","kind":"docs"},{"label":"CodeMirror 6","url":"https://codemirror.net/","kind":"tutorial"}]'::jsonb, ARRAY['javascript','sparql','gnome','rdf','ide']::text[]),
  ('gsoc-wikimedia-pagetriage-feed', 'Improve Wikimedia PageTriage Feed Search and Filtering', 'Upgrade MediaWiki''s New Pages Feed (the PageTriage extension) with AI-based topic prediction via the ORES API, keyword search, page-view filters, and similarity matching against previously deleted pages. The goal is to help reviewers triage thousands of new English Wikipedia articles per day.', 'Clone mediawiki/extensions/PageTriage from gerrit.wikimedia.org and bring up a local MediaWiki via the official Docker setup at mediawiki.org/wiki/MediaWiki-Docker. The Vue.js frontend lives under modules/ext.pageTriage.newPagesFeed; the PHP backend hooks into ApiPageTriageList.

ORES is reachable at ores.wikimedia.org with no auth — query the drafttopic and articlequality models for any pageid and integrate the scores as filter facets. Page-view filters come from the wikimedia/page-view REST API at wikimedia.org/api/rest_v1. Add similarity search by indexing recently deleted titles with a TF-IDF model in MySQL FULLTEXT or a small Elasticsearch instance.

Introduce yourself on the Wikimedia phabricator and #wikimedia-dev on Libera Chat IRC, and on the wikitech-l list. The PageTriage product manager and engineering team review patches in Gerrit — keep changes small and reference the relevant Phabricator task.', 'OpenSource', 'intermediate', 'Wikimedia', 'GSoC', 'GSoC 2024', 'https://www.mediawiki.org/wiki/Google_Summer_of_Code/2024', '[{"label":"Wikimedia page-view API","url":"https://wikimedia.org/api/rest_v1/"}]'::jsonb, '[{"label":"PageTriage source","url":"https://gerrit.wikimedia.org/g/mediawiki/extensions/PageTriage","kind":"repo"},{"label":"ORES models","url":"https://www.mediawiki.org/wiki/ORES","kind":"docs"}]'::jsonb, ARRAY['php','vuejs','mediawiki','wikipedia','ml']::text[]),
  ('gsoc-wikimedia-scribe-data-cli', 'Scribe-Data: Multi-Purpose Wikidata Language Pack CLI', 'Refactor Scribe-Data into a general-purpose command-line tool that extracts language packs from Wikidata via SPARQL. The CLI should produce data files for the Scribe iOS, Android and browser keyboard apps as well as third-party language-learning projects.', 'Read scribe-org/Scribe-Data on GitHub; the existing SPARQL queries under src/scribe_data/extract_transform are the starting point. Wrap them in a click or Typer-based CLI that takes a language code and an output format (JSON, CSV, SQLite). The Wikidata Query Service at query.wikidata.org returns results over HTTP — be mindful of the 60-second timeout.

Design the schema so that consumers (iOS Scribe, scribe-android, third parties) get the same fields regardless of source language. Add unit tests with vcrpy so SPARQL results are recorded and the test suite stays offline. Document the data model in docs/.

Introduce yourself in the Scribe-Org Matrix room linked from the README and on the wikitech-l list. Mentors Andrew Tavis McAllister and the Scribe community lead reviews. Skills: Python, SPARQL, and familiarity with linguistic data (parts of speech, conjugation tables).', 'OpenSource', 'intermediate', 'Wikimedia', 'GSoC', 'GSoC 2024', 'https://www.mediawiki.org/wiki/Google_Summer_of_Code/2024', '[{"label":"Wikidata Query Service","url":"https://query.wikidata.org/"}]'::jsonb, '[{"label":"Scribe-Data repo","url":"https://github.com/scribe-org/Scribe-Data","kind":"repo"},{"label":"SPARQL primer","url":"https://www.wikidata.org/wiki/Wikidata:SPARQL_tutorial","kind":"tutorial"}]'::jsonb, ARRAY['python','sparql','wikidata','cli','linguistics']::text[]),
  ('gsoc-apache-kvrocks-timeseries', 'Apache Kvrocks: RedisTimeSeries-Compatible Time Series', 'Implement RedisTimeSeries-compatible commands inside Kvrocks — the Redis-compatible store built on RocksDB. Because the storage engine is on-disk LSM rather than in-memory, the algorithms for chunking, downsampling and retention must be designed from scratch.', 'Clone apache/kvrocks and read src/commands and src/types — that is where Redis-protocol commands and the per-type storage live. The matching RedisTimeSeries spec is at redis.io/docs/data-types/timeseries; mirror the TS.CREATE, TS.ADD, TS.RANGE and TS.MRANGE surface area first.

Design the on-disk layout up front: an LSM tree wants append-friendly keys, so you will likely key by (series-id, time-bucket) with a separate metadata column family. Add unit tests that pit your implementation against a real RedisTimeSeries deployment with redis-tssr-benchmark for cross-checking.

Introduce yourself on dev@kvrocks.apache.org and the Kvrocks Slack. Mentor Mingyang Liu (twice@apache.org) leads architectural reviews. Skills: modern C++17, LSM internals, and time-series fundamentals (Gorilla compression is a stretch goal worth reading about).', 'OpenSource', 'advanced', 'Apache Software Foundation', 'GSoC', 'GSoC 2024', 'https://cwiki.apache.org/confluence/display/COMDEV/GSoC+2024+Ideas+list', '[]'::jsonb, '[{"label":"Apache Kvrocks","url":"https://github.com/apache/kvrocks","kind":"repo"},{"label":"RedisTimeSeries docs","url":"https://redis.io/docs/data-types/timeseries/","kind":"docs"}]'::jsonb, ARRAY['cpp','rocksdb','redis','time-series','databases']::text[]),
  ('gsoc-apache-nuttx-nand-flash', 'Apache NuttX NAND Flash Subsystem', 'Add a complete NAND-flash storage stack to the NuttX RTOS — bad-block mapping, wear-levelling and a filesystem layer tuned for cheap raw NAND parts used in microcontrollers. NuttX already supports NOR; NAND has been a long-standing gap.', 'Read drivers/mtd and fs/ in apache/nuttx — NuttX''s MTD layer is the abstraction you will extend. Study existing comparable subsystems in Zephyr (subsys/fs/fs.c and drivers/flash) and Linux''s UBI/UBIFS for design references. Pick a target chip with a public datasheet (the SAMA5D2 NAND controller is a popular choice) and an evaluation board you can flash.

Write the bad-block table format first, then the wear-leveller, then mount existing filesystems (SmartFS, LittleFS) on top. NuttX''s build is Make-based with Kconfig; nsh on QEMU is sufficient for the early iterations of the BBT logic. Use ftl_test and nxffs_test as templates for your test cases.

Introduce yourself on dev@nuttx.apache.org and the Apache NuttX Discord. Mentor Alan Carvalho de Assis (acassis@apache.org) maintains the surrounding storage code. Skills: embedded C, datasheet reading, comfort with hardware bring-up.', 'OpenSource', 'advanced', 'Apache Software Foundation', 'GSoC', 'GSoC 2024', 'https://cwiki.apache.org/confluence/display/COMDEV/GSoC+2024+Ideas+list', '[]'::jsonb, '[{"label":"Apache NuttX","url":"https://github.com/apache/nuttx","kind":"repo"},{"label":"NuttX porting guide","url":"https://nuttx.apache.org/docs/latest/","kind":"docs"}]'::jsonb, ARRAY['c','embedded','rtos','flash','filesystems']::text[]),
  ('gsoc-apache-opendal-virtiofs', 'Apache OpenDAL Virtual File System for VMs', 'Build a VirtioFS-based daemon that exposes any OpenDAL-supported backend (S3, GCS, Azure Blob, HDFS) as a regular filesystem to virtual machines. The daemon brokers metadata operations, manages caches and lets ML workloads in VMs read and write checkpoints over familiar POSIX calls.', 'Read apache/opendal — the Rust crate under core/ is the data-plane you will wrap. Then read the VirtioFS spec at docs.kernel.org/filesystems/virtiofs.html and the rust-vmm/vhost-user-fs crate, which is the reference vhost-user filesystem daemon you will fork. The OVFS prototype that earlier GSoC contributors started lives at apache/opendal-ovfs.

Mount your daemon inside a QEMU guest using -chardev socket and virtiofsd, then run fio and pytorch checkpoint loops to confirm the cache layer pays off. Skills you need: solid Rust async, kernel filesystem semantics (inode lookup, dirent iteration), and patience for vmm tooling.

Introduce yourself on dev@opendal.apache.org and the Apache OpenDAL Discord linked from the README. Mentor Xuanwo reviews most patches personally. Plan for 350 hours and a multi-stage merge: skeleton, read-only, cache, write-back.', 'OpenSource', 'advanced', 'Apache Software Foundation', 'GSoC', 'GSoC 2024', 'https://cwiki.apache.org/confluence/display/COMDEV/GSoC+2024+Ideas+list', '[]'::jsonb, '[{"label":"Apache OpenDAL","url":"https://github.com/apache/opendal","kind":"repo"},{"label":"VirtioFS specification","url":"https://docs.kernel.org/filesystems/virtiofs.html","kind":"docs"}]'::jsonb, ARRAY['rust','virtio','filesystems','vmm','storage']::text[]),
  ('gsoc-owasp-juice-shop-test-harmonization', 'OWASP Juice Shop Test Suite Harmonization', 'Replace Juice Shop''s aging Frisby.js integration tests with a modern framework that aligns with the Cypress end-to-end suite added in GSoC 2022. The goal is one consistent assertion style across unit, API and UI layers, with reliable CI.', 'Fork juice-shop/juice-shop and run npm install, npm test, npm run frisby — you will quickly meet the flakiness the project is famous for. Read test/api/, that is where Frisby specs live. Map every assertion to its Cypress, Vitest or Supertest equivalent and keep a checklist as you migrate.

Maintain green CI throughout: convert one route at a time, leave the corresponding Frisby spec in place behind a feature flag until the new one matches, then delete. Skills required: JavaScript/TypeScript, Node.js, Express, and the patience to read HTTP traces. Familiarity with the OWASP Top Ten helps you understand what the tests are actually checking.

Introduce yourself on juice-shop''s #juice-shop OWASP Slack channel and ping mentors Bjoern Kimminich, Shubham Palriwala and Jannik Hollenbach. They review pull requests within days. Plan for 175 hours.', 'OpenSource', 'intermediate', 'OWASP', 'GSoC', 'GSoC 2024', 'https://owasp.org/www-community/initiatives/gsoc/gsoc2024ideas', '[]'::jsonb, '[{"label":"Juice Shop repository","url":"https://github.com/juice-shop/juice-shop","kind":"repo"},{"label":"OWASP GSoC entry","url":"https://owasp.org/www-community/initiatives/gsoc/","kind":"docs"}]'::jsonb, ARRAY['typescript','nodejs','testing','security','owasp']::text[]),
  ('gsoc-owasp-securecodebox-cli', 'OWASP secureCodeBox CLI', 'Build a command-line tool for OWASP secureCodeBox — a Kubernetes-native security scanning platform. The CLI should list scans, inspect findings, trigger ad-hoc scans and manage Custom Resources without forcing users into kubectl.', 'Read secureCodeBox/secureCodeBox on GitHub, especially operator/ and the CRDs under operator/apis/. Choose Go and the controller-runtime client — that is what the operator itself uses, so the CRD types are already published as a Go module you can import.

Scaffold the CLI with cobra: scbctl scan run zap-baseline-scan --target https://example.com, scbctl findings list, scbctl scan logs. Mirror kubectl''s verb-noun structure so users feel at home. Add an integration test harness that spins up a kind cluster with the operator installed and runs the CLI against it.

Introduce yourself on the secureCodeBox Slack (linked from the README) and on the OWASP Slack #securecodebox channel. Mentors Jannik Hollenbach and Robert Felber respond there. Skills: Go, Kubernetes client-go, CI/CD basics. Plan for 175 hours.', 'OpenSource', 'intermediate', 'OWASP', 'GSoC', 'GSoC 2024', 'https://owasp.org/www-community/initiatives/gsoc/gsoc2024ideas', '[]'::jsonb, '[{"label":"secureCodeBox repo","url":"https://github.com/secureCodeBox/secureCodeBox","kind":"repo"},{"label":"cobra CLI library","url":"https://github.com/spf13/cobra","kind":"tutorial"}]'::jsonb, ARRAY['go','kubernetes','security','cli','owasp']::text[]),
  ('gsoc-cncf-prometheus-created-timestamp', 'Prometheus Created Timestamp in Text Format', 'Implement optional created-timestamp support in the Prometheus text exposition format and in OpenMetrics. Counters and histograms need a reset-detection timestamp to make rate calculations resilient to scrape restarts, and the text format is the last holdout.', 'Read prometheus/prometheus and prometheus/client_golang. The text parser sits under model/textparse — that is the file you will extend. The OpenMetrics format already supports _created metrics; mirror that semantic for the legacy text format with a small surface change.

Start by reading the design discussion in the prometheus/proposals repository — the created-timestamp design doc is the contract. Then write a failing test in textparse_test.go and a corresponding scrape integration test under scrape/. The Go client libraries also need updating so exporters can emit the new field.

Introduce yourself on the #prometheus-dev channel in CNCF Slack and the prometheus-developers Google Group. Mentor Bartek Plotka leads observability; Arthur Silva Sens and Daniel Hrabovcak co-mentor. Skills: Go, HTTP, comfort with stable-API design — anything you ship will be parsed by every Prometheus user.', 'OpenSource', 'intermediate', 'CNCF', 'GSoC', 'GSoC 2024', 'https://github.com/cncf/mentoring/blob/main/programs/summerofcode/2024.md', '[]'::jsonb, '[{"label":"Prometheus source","url":"https://github.com/prometheus/prometheus","kind":"repo"},{"label":"OpenMetrics spec","url":"https://github.com/OpenObservability/OpenMetrics/blob/main/specification/OpenMetrics.md","kind":"docs"}]'::jsonb, ARRAY['go','prometheus','observability','cncf','metrics']::text[]),
  ('gsoc-cncf-jaeger-v2-deployment', 'Jaeger v2 Deployment Options', 'Produce production-ready deployment artifacts for Jaeger v2 — the OpenTelemetry-Collector-based rewrite of the distributed tracing system. Deliverables include an updated Kubernetes operator, a Helm chart and a Homebrew formula, all with documentation.', 'Read jaegertracing/jaeger and jaegertracing/jaeger-operator. Jaeger v2 is built on the OpenTelemetry Collector, so a working knowledge of open-telemetry/opentelemetry-collector and its component model is mandatory. Start by reading the v2 architecture proposal in the jaeger repository''s docs/architecture/v2 directory.

Fork the operator and add a JaegerV2 CRD. Mirror the existing v1 deployment knobs (storage, sampling, ingester) on top of the new collector configuration schema. The Helm chart lives at jaegertracing/helm-charts — add an analogous v2 chart alongside the v1 one. Test on kind clusters with otel-cli emitting traces.

Introduce yourself in the #jaeger channel of CNCF Slack and on the jaeger-tracing Google Group. Mentor Yuri Shkuro (the original Jaeger creator) and Jonah Kowall both review there. Skills: Go, Kubernetes, scripting, and CI/CD pipelines. Plan for 350 hours and incremental shipping.', 'OpenSource', 'advanced', 'CNCF', 'GSoC', 'GSoC 2024', 'https://github.com/cncf/mentoring/blob/main/programs/summerofcode/2024.md', '[]'::jsonb, '[{"label":"Jaeger repository","url":"https://github.com/jaegertracing/jaeger","kind":"repo"},{"label":"OpenTelemetry Collector","url":"https://github.com/open-telemetry/opentelemetry-collector","kind":"repo"}]'::jsonb, ARRAY['go','kubernetes','tracing','cncf','observability']::text[]),
  ('gsoc-cncf-falco-event-generator', 'Falco Event Generator and Performance Benchmarking', 'Upgrade Falco''s event-generator utility to drive systematic performance benchmarks of the runtime security engine, then wire those benchmarks into CI so regressions surface on every pull request. Falco needs reproducible numbers under realistic syscall load.', 'Read falcosecurity/event-generator and falcosecurity/falco. The event-generator is a Go binary that simulates malicious behaviour (shell-in-container, sensitive-file-reads, etc.); extend it with new scenarios and stable rate controls. Then build a benchmark harness that runs Falco with the eBPF and kmod drivers across configurable event mixes.

Use GitHub Actions matrix builds to run the benchmarks on every PR and post the CPU and dropped-event numbers as a PR comment. Compare against a baseline checked into the repo so reviewers can see deltas. Skills: Go, eBPF basics, a clear sense of what makes a benchmark statistically meaningful.

Introduce yourself on the Falco CNCF Slack channel and falco-devel on Google Groups. Mentors Jason Dellaluce and Aldo Lacuku are the engine maintainers. Plan for 350 hours.', 'OpenSource', 'advanced', 'CNCF', 'GSoC', 'GSoC 2024', 'https://github.com/cncf/mentoring/blob/main/programs/summerofcode/2024.md', '[]'::jsonb, '[{"label":"Falco event-generator","url":"https://github.com/falcosecurity/event-generator","kind":"repo"},{"label":"Falco main repo","url":"https://github.com/falcosecurity/falco","kind":"repo"}]'::jsonb, ARRAY['go','ebpf','security','benchmarks','cncf']::text[]),
  ('gsoc-swift-macros-vscode', 'Swift Macro Expansion in VS Code', 'Bring Swift macro expansion previews to Visual Studio Code by extending the Swift VS Code extension so developers can inspect the generated code in-editor without rerunning swift build. Support nested expansion and semantic navigation into the generated source.', 'Read the swift-server/vscode-swift extension and the swiftlang/sourcekit-lsp protocol layer. SourceKit-LSP already implements textDocument/expandMacro — wire it into a VS Code WebView that displays the expansion alongside the source, with selection-synced highlights.

Write a small TypeScript client that issues the LSP request and renders the response via Monaco''s diff editor. Stretch goals: jump-to-definition across the macro boundary and recursive expansion of nested macro calls. Test against the swift-syntax test fixtures and the OSLog macro that ships with the standard library.

Introduce yourself on the Swift Forums (forums.swift.org) under the Tooling category and on the swift-language Slack. Mentors Alex Hoppen and Adam Fowler are responsive. Skills: Swift fluency, comfortable TypeScript, and a working understanding of LSP.', 'OpenSource', 'intermediate', 'Swift', 'GSoC', 'GSoC 2024', 'https://www.swift.org/gsoc2024/', '[]'::jsonb, '[{"label":"VS Code Swift extension","url":"https://github.com/swift-server/vscode-swift","kind":"repo"},{"label":"SourceKit-LSP","url":"https://github.com/swiftlang/sourcekit-lsp","kind":"repo"}]'::jsonb, ARRAY['swift','typescript','vscode','lsp','macros']::text[]),
  ('gsoc-swift-macros-webassembly', 'Building Swift Macros with WebAssembly', 'Make Swift macros portable by compiling them to WebAssembly so the compiler can run macro plugins inside a wasm sandbox instead of as host-platform binaries. This removes the need to ship per-OS, per-architecture macro plugin binaries.', 'Read swiftlang/swift, particularly the macro plugin protocol in lib/AST/PluginRegistry.cpp and the SwiftWasm fork''s standard library bindings. The macro plugin currently runs as a subprocess speaking a JSON-RPC dialect — your job is to swap that subprocess for a wasmtime or wasmer embedding inside the compiler.

Prototype with a single macro from swift-syntax (StringifyMacro is the canonical hello-world). Compile it with the SwiftWasm toolchain, host it via wasmtime, and prove the compiler can drive expansion end-to-end. Then generalise the loader and write a manifest format so multiple macros can live in one wasm module.

Introduce yourself on forums.swift.org in the Compiler and SwiftWasm categories. Mentor Doug Gregor leads the macro implementation. Skills: Swift, C++, an interest in compilers, and willingness to learn the WebAssembly Component Model.', 'OpenSource', 'advanced', 'Swift', 'GSoC', 'GSoC 2024', 'https://www.swift.org/gsoc2024/', '[]'::jsonb, '[{"label":"swift-syntax","url":"https://github.com/swiftlang/swift-syntax","kind":"repo"},{"label":"SwiftWasm","url":"https://book.swiftwasm.org/","kind":"docs"}]'::jsonb, ARRAY['swift','cpp','webassembly','compilers','macros']::text[]),
  ('gsoc-haiku-go-port', 'Port the Go Programming Language to Haiku', 'Upstream a Go toolchain port to Haiku, the BeOS-inspired open-source desktop OS. The port needs Go''s runtime, garbage collector and goroutine scheduler running natively against Haiku''s POSIX-plus-BeAPI surface, plus net and os support.', 'Read the existing partial port at github.com/haiku/buildtools and the haiku-os mailing list archives for prior attempts. The Go runtime''s portability layer lives in src/runtime/os_*.go and src/runtime/sys_*_*.s — you will write os_haiku.go and assembler stubs for amd64 first. Use Haiku''s POSIX layer where possible, fall back to BeAPI syscalls otherwise.

Bootstrap with a cross-compiled Go from Linux, then iterate on net and signal handling — those are where every Unix-like port stumbles. Run the standard test suite under all.bash until it is green; expect to file upstream patches against runtime/cgo.

Introduce yourself on Haiku''s Discord and the haiku-development mailing list. Most maintainers also hang out on #haiku on Libera Chat IRC. Skills: solid C, working Go, willingness to read AT and Intel syntax assembly, and ELF binary internals.', 'OpenSource', 'advanced', 'Haiku', 'GSoC', 'GSoC 2024', 'https://www.haiku-os.org/community/gsoc/2024/ideas/', '[]'::jsonb, '[{"label":"Haiku source","url":"https://github.com/haiku/haiku","kind":"repo"},{"label":"Go runtime porting guide","url":"https://go.dev/wiki/PortingPolicy","kind":"docs"}]'::jsonb, ARRAY['go','c','haiku','operating-systems','ports']::text[]),
  ('gsoc-haiku-webkit-media', 'Haiku WebKit Audio and Video Support', 'Integrate Haiku''s Media Kit into the WebKit port so YouTube and other HTML5 video sites play natively in WebPositive. Today most media element playback is missing or stubbed; the work routes HTMLMediaElement through Haiku''s BMediaFile pipeline.', 'Clone haikuports''s webkit recipe and read the upstream WebKit MediaPlayerPrivate hierarchy under Source/WebCore/platform/graphics/. Pick GStreamer''s port as the reference implementation — its MediaPlayerPrivateGStreamer class is the closest analogue to what you will write for Haiku.

Write MediaPlayerPrivateHaiku, backed by BMediaFile and BMediaTrack from Haiku''s Media Kit. Start with progressive download MP4 playback, then add HLS via the Adaptive Media library, then audio-only streams. Cross-check with the manual WebKit layout tests under LayoutTests/media.

Introduce yourself on Haiku''s Discord #webpositive channel and the haiku-development list. Mentors PulkoMandy and the WebKit port maintainers review patches. Skills: userland C++, multimedia plumbing, and the ability to navigate a million-line codebase without losing the thread.', 'OpenSource', 'intermediate', 'Haiku', 'GSoC', 'GSoC 2024', 'https://www.haiku-os.org/community/gsoc/2024/ideas/', '[]'::jsonb, '[{"label":"Haiku WebKit recipe","url":"https://github.com/haikuports/haikuports/tree/master/app-text/webkit","kind":"repo"},{"label":"WebKit project","url":"https://webkit.org/","kind":"docs"}]'::jsonb, ARRAY['cpp','haiku','webkit','media','browser']::text[]),
  ('gsoc-fossi-openroad-python-bindings', 'Python Bindings for OpenROAD', 'Expose OpenROAD''s chip-design data model — the OpenDB (odb) library — as a first-class Python package, then extend the bindings to the rest of the OpenROAD flow. The goal is to let designers script place-and-route entirely from Python and pip-install the result.', 'Clone The-OpenROAD-Project/OpenROAD and read src/odb. SWIG bindings already exist but are tightly coupled to the embedded TCL interpreter; your job is to extract them, build odb as a standalone shared library, and produce a pip-installable wheel via pybind11 or nanobind.

Set up a Conda environment using the OpenROAD-flow-scripts; the build is CMake with many third-party dependencies. Once odb is importable, replicate for db_sta, gui and rsz. Add a small example notebook that loads a LEF/DEF design, runs detailed placement and reports timing.

Introduce yourself on the OpenROAD Slack (openroad.slack.com) and the FOSSi Foundation Element room. Mentors Johan Euphrosine and Matt Liberty drive the Python effort. Skills: C++ build engineering, Python packaging, Conda recipe writing.', 'OpenSource', 'advanced', 'FOSSi Foundation', 'GSoC', 'GSoC 2024', 'https://fossi-foundation.org/gsoc/gsoc24-ideas', '[]'::jsonb, '[{"label":"OpenROAD repo","url":"https://github.com/The-OpenROAD-Project/OpenROAD","kind":"repo"},{"label":"pybind11 docs","url":"https://pybind11.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['cpp','python','eda','chip-design','bindings']::text[]),
  ('gsoc-fossi-openrisc-linux-features', 'OpenRISC Linux Kernel Feature Development', 'Land three long-standing OpenRISC Linux kernel features: restartable sequences (rseq), the cacheinfo API, and virtio device support. Each unblocks a slice of modern userspace — glibc, perf, and standard cloud-style guest images — on OpenRISC hardware.', 'Read the OpenRISC architecture port at arch/openrisc in torvalds/linux. The rseq implementation belongs in arch/openrisc/kernel; cross-reference arch/arm64/kernel/rseq.c and arch/x86/kernel/rseq.c. cacheinfo belongs under drivers/base/cacheinfo with an arch hook; virtio support means a working virtio-mmio driver path on the QEMU openrisc target.

Build a cross toolchain following openrisc.io and bring up Linux under qemu-system-or1k. Iterate via git send-email to openrisc@lists.librecores.org and linux-openrisc on Patchwork. Each feature is a candidate for a full kernel cycle, so expect rebases.

Introduce yourself on openrisc@lists.librecores.org and ping mentor Stafford Horne. Skills: kernel C, OpenRISC assembly basics, comfort with kernel patch etiquette and Documentation/process/.', 'OpenSource', 'advanced', 'FOSSi Foundation', 'GSoC', 'GSoC 2024', 'https://fossi-foundation.org/gsoc/gsoc24-ideas', '[]'::jsonb, '[{"label":"Linux source","url":"https://github.com/torvalds/linux","kind":"repo"},{"label":"OpenRISC site","url":"https://openrisc.io/","kind":"docs"}]'::jsonb, ARRAY['c','linux-kernel','openrisc','embedded','assembly']::text[]),
  ('gsoc-sympy-assumptions-overhaul', 'SymPy Assumptions System Overhaul', 'Replace SymPy''s legacy assumptions engine with the newer logical-inference implementation so queries like ask(Q.positive(x*y), Q.positive(x) & Q.positive(y)) are consistent across the codebase. The legacy system has well-known correctness gaps the rewrite would close.', 'Read sympy/sympy/assumptions and the older sympy/sympy/core/assumptions.py. The new system uses Boolean satisfiability via the satask module; the old one threads through every Basic subclass. Pick one assumption (positivity is the easiest) and migrate every call site to ask() so you can quantify the perf and correctness deltas.

Write a benchmark suite using SymPy''s asv harness before and after to catch regressions — symbolic code is notoriously easy to slow down. Read the design discussions in sympy/sympy issues 7807 and 21171 to understand prior attempts.

Introduce yourself on the sympy mailing list at groups.google.com/g/sympy and the SymPy Gitter. Mentors Aaron Meurer and Oscar Benjamin guide the assumptions effort. Skills: Python, Boolean algebra, deep familiarity with SymPy''s Basic class hierarchy. Plan for 350 hours.', 'OpenSource', 'advanced', 'SymPy', 'GSoC', 'GSoC 2024', 'https://github.com/sympy/sympy/wiki/GSoC-Ideas', '[]'::jsonb, '[{"label":"SymPy repository","url":"https://github.com/sympy/sympy","kind":"repo"},{"label":"SymPy assumptions docs","url":"https://docs.sympy.org/latest/modules/assumptions/index.html","kind":"docs"}]'::jsonb, ARRAY['python','sympy','logic','symbolic-math','algorithms']::text[]),
  ('gsoc-sympy-polynomial-gcd', 'Sparse Polynomial GCD Algorithms in SymPy', 'Implement modern sparse-polynomial GCD algorithms (Zippel, EEZ-GCD, Brown) inside SymPy''s polys module. Polynomial GCD underlies solvers, integration and matrix simplification, so improvements ripple through the rest of the library.', 'Read sympy/polys, particularly polys/polyfuncs.py and polys/galoistools.py. The current dense GCD lives in heugcd.py; you will add sparse variants that operate on dictionary representations. Algorithm references: Geddes Czapor Labahn''s textbook chapter 7, and the Zippel 1979 paper.

Profile against benchmarks/polys.py and against test cases pulled from real-world solver issues. Add doctests that exercise the new code paths and benchmarks that pin performance going forward. Skills: Python, abstract algebra fluency, careful complexity analysis.

Introduce yourself on the sympy mailing list and Gitter and ping mentors Aaron Meurer and Oscar Benjamin. Plan for 350 hours with frequent algebra-textbook detours.', 'OpenSource', 'advanced', 'SymPy', 'GSoC', 'GSoC 2024', 'https://github.com/sympy/sympy/wiki/GSoC-Ideas', '[]'::jsonb, '[{"label":"SymPy polys docs","url":"https://docs.sympy.org/latest/modules/polys/index.html","kind":"docs"},{"label":"SymPy benchmarks","url":"https://github.com/sympy/sympy_benchmarks","kind":"repo"}]'::jsonb, ARRAY['python','algebra','algorithms','sympy','performance']::text[]),
  ('gsoc-octave-statistics-anova', 'anova Object for the GNU Octave Statistics Package', 'Add an anova classdef — together with its accompanying methods — to Octave''s statistics package so users can perform full Analysis of Variance with the same ergonomic API as MATLAB. The work covers one-way, two-way and repeated-measures designs.', 'Read the octave-statistics package on Octave Forge and clone gnu-octave/statistics on GitHub. Study how the existing fitlm and LinearModel classdefs are wired — your anova class follows the same shape. The MATLAB documentation for anova1, anova2 and anovan defines the API contract you should match where reasonable.

The Octave classdef system is still maturing; expect to file bug reports against the core interpreter as you go. Write BIST (built-in self-test) blocks in the .m files themselves so make check exercises every code path. Cross-validate results against R''s aov() on the canonical datasets (iris, mtcars).

Introduce yourself on the octave-maintainers list and the #octave IRC channel on Libera Chat. Mentor Andreas Bertsatos drives the statistics package. Skills: Octave/MATLAB, statistics (Type I-III sums of squares matter), classdef syntax.', 'OpenSource', 'advanced', 'GNU Octave', 'GSoC', 'GSoC 2024', 'https://wiki.octave.org/Summer_of_Code_Project_Ideas', '[]'::jsonb, '[{"label":"Octave statistics package","url":"https://github.com/gnu-octave/statistics","kind":"repo"},{"label":"Octave GSoC entry page","url":"https://wiki.octave.org/Summer_of_Code","kind":"docs"}]'::jsonb, ARRAY['octave','matlab','statistics','anova','scientific-computing']::text[]),
  ('gsoc-kde-kdenlive-subtitles-ass', 'Advanced ASS Subtitle Support in Kdenlive', 'Bring full Advanced SubStation Alpha (ASS) styling into Kdenlive''s subtitle track — bold, italics, colour, font, positioning and speaker attribution — so editors can produce broadcast-quality captions inside the timeline instead of round-tripping through Aegisub.', 'Read invent.kde.org/multimedia/kdenlive, specifically src/bin/model/subtitlemodel.cpp and the MLT-side subtitle filters in MltController. Kdenlive''s playback runs MLT, which already speaks libass; your job is to expose the styling beyond the current SRT-only baseline up through Qt models and into the timeline UI.

Design the data model first: a SubtitleEvent with style references, then a SubtitleStyle catalogue. Render the timeline preview by passing the generated ASS file to MLT''s avfilter=subtitles=. Add a styling sidebar with font, colour, outline and positioning controls.

Introduce yourself in #kdenlive:kde.org on Matrix and on kdenlive@kde.org. Mentor Jean-Baptiste Mardelle is the project lead. Skills: C++, Qt, comfort with the MLT framework and at least passing knowledge of the ASS spec at aegisub.org/docs.', 'OpenSource', 'intermediate', 'KDE', 'GSoC', 'GSoC 2024', 'https://community.kde.org/GSoC/2024/Ideas', '[]'::jsonb, '[{"label":"Kdenlive source","url":"https://invent.kde.org/multimedia/kdenlive","kind":"repo"},{"label":"ASS specification","url":"http://www.tcax.org/docs/ass-specs.htm","kind":"docs"}]'::jsonb, ARRAY['cpp','qt','kdenlive','video-editing','subtitles']::text[]),
  ('gsoc-kde-kstars-ekos-pipeline', 'Ekos Node-Based Imaging Pipeline for KStars', 'Build a node-based imaging pipeline inside KStars/Ekos so astrophotographers can compose live-stacking flows: bias subtraction, flat-fielding, registration and stacking all chain together as DAG nodes. Today Ekos hardcodes the order; the rewrite makes it configurable.', 'Clone invent.kde.org/education/kstars and study kstars/ekos/capture/ and kstars/fitsviewer/. The node model should mirror Blender''s compositor: each node has typed inputs and outputs, the user wires them together, and the executor walks the DAG when a new frame arrives from the camera via INDI.

Define a small set of starter nodes — DarkFrame, FlatField, Register, Stack — and one operator node, e.g. Histogram. Use Qt Quick for the node editor canvas. Run against a real camera through indilib''s simulator drivers or saved FITS data.

Introduce yourself on the kstars-devel mailing list and the KStars Telegram group. Mentor Jasem Mutlaq leads Ekos and reviews every patch. Skills: C++, Qt, image processing fundamentals, and a working interest in astrophotography.', 'OpenSource', 'advanced', 'KDE', 'GSoC', 'GSoC 2024', 'https://community.kde.org/GSoC/2024/Ideas', '[]'::jsonb, '[{"label":"KStars source","url":"https://invent.kde.org/education/kstars","kind":"repo"},{"label":"INDI library","url":"https://www.indilib.org/","kind":"docs"}]'::jsonb, ARRAY['cpp','qt','astronomy','image-processing','kstars']::text[]),
  ('gsoc-jenkins-bearer-tokens-git', 'Bearer Token Authentication for Jenkins Git Plugins', 'Add bearer-token authentication to the Jenkins Git and Git Client plugins so build agents can pull from GitHub Apps, GitLab project access tokens and Bitbucket workspace tokens without faking SSH or username-password credentials.', 'Read jenkinsci/git-plugin and jenkinsci/git-client-plugin. The credential abstraction sits in the Credentials Provider API; introduce a new BearerTokenCredentials type and teach the JGit and CLI git invocations to pass it via the appropriate header or askpass helper.

GitHub Apps need a short-lived installation token; mirror the approach in the github-branch-source-plugin so token refresh is cached and thread-safe. Add tests using the Jenkins test harness (JenkinsRule) with a stubbed Git server.

Introduce yourself on jenkinsci-dev and the #jenkins-developers channel on Discord. Mentors Mark Waite, Kris Stern and Valentin Delaye review there. Skills: Java, basic OAuth and JWT, plus an understanding of how Jenkins credentials are scoped to folders and items.', 'OpenSource', 'intermediate', 'Jenkins', 'GSoC', 'GSoC 2024', 'https://www.jenkins.io/projects/gsoc/2024/project-ideas/', '[]'::jsonb, '[{"label":"Jenkins git-plugin","url":"https://github.com/jenkinsci/git-plugin","kind":"repo"},{"label":"Jenkins git-client-plugin","url":"https://github.com/jenkinsci/git-client-plugin","kind":"repo"}]'::jsonb, ARRAY['java','jenkins','git','authentication','plugins']::text[]),
  ('gsoc-apache-skywalking-banyandb-ui', 'Apache SkyWalking BanyanDB Cluster Overview UI', 'Design and build a Vue 3 dashboard that surfaces BanyanDB cluster health — node uptime, CPU/memory/disk usage, network ports — with auto-refresh. BanyanDB is SkyWalking''s purpose-built observability database and currently lacks an operator-friendly UI.', 'Read apache/skywalking-banyandb and apache/skywalking-booster-ui. The booster UI is Vue 3 plus Vite, talking to BanyanDB through a REST gateway. Add a /cluster route with cards per node, sparkline charts via vue-echarts, and a polling layer that uses the existing API client.

Bring up a multi-node BanyanDB cluster with the Docker Compose setup in the repo to test against realistic data. Mirror the layout conventions of the existing dashboards so the new view feels native.

Introduce yourself on dev@skywalking.apache.org and the Apache SkyWalking Slack. Mentor Hongtao Gao reviews. Skills: Vue 3, Vite, REST API consumption, and a working sense for observability dashboards.', 'OpenSource', 'intermediate', 'Apache Software Foundation', 'GSoC', 'GSoC 2024', 'https://cwiki.apache.org/confluence/display/COMDEV/GSoC+2024+Ideas+list', '[]'::jsonb, '[{"label":"SkyWalking BanyanDB","url":"https://github.com/apache/skywalking-banyandb","kind":"repo"},{"label":"SkyWalking Booster UI","url":"https://github.com/apache/skywalking-booster-ui","kind":"repo"}]'::jsonb, ARRAY['vue','typescript','skywalking','observability','dashboard']::text[]),
  ('kaggle-digit-recognizer', 'Digit Recognizer', 'Classify 28x28 grayscale images of handwritten digits 0-9 from the classic MNIST dataset. The competition is Kaggle''s permanent getting-started CV benchmark and accepts categorisation accuracy on a held-out test set.', 'Start with a tiny convolutional net in PyTorch or tf.keras — two Conv2D + MaxPool blocks followed by a Dense(10) softmax head hits 99 percent on the public leaderboard inside ten epochs on a free Kaggle GPU. Normalize pixels to 0-1, reshape to (28,28,1), and one-hot encode the label column.

The single biggest jump comes from data augmentation — rotation 10 degrees, width and height shift 0.1, and slight zoom. Without it the network overfits the 42000 training rows. Use ImageDataGenerator or torchvision.transforms.RandomAffine.

The public test set is small enough that a 5-fold CV ensemble of ResNet-style nets pushes you past 99.7. Pitfall — do not shuffle the labels column when reshaping; many beginners flatten label + pixels together and feed garbage to the model.', 'AI/ML', 'beginner', 'Kaggle', 'Kaggle', NULL, 'https://www.kaggle.com/competitions/digit-recognizer', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/digit-recognizer/data","format":"csv"}]'::jsonb, '[{"label":"Keras MNIST CNN tutorial","url":"https://keras.io/examples/vision/mnist_convnet/","kind":"tutorial"}]'::jsonb, ARRAY['python','pytorch','cnn','computer-vision','mnist']::text[]),
  ('kaggle-spaceship-titanic', 'Spaceship Titanic', 'Binary classification — predict which passengers were transported to an alternate dimension after the Spaceship Titanic collided with a spacetime anomaly. The follow-up to the classic Titanic getting-started competition, with richer features and more missing values.', 'A LightGBM or XGBoost baseline on engineered features clears the 0.80 mark. Split the PassengerId into group and number — passengers sharing a group ID share a fate roughly 70 percent of the time, which is the single most predictive feature. Decompose Cabin into Deck, Num, Side.

Missing values are everywhere — about 2 percent per column. Do NOT impute blindly. CryoSleep passengers have zero spending; if RoomService and FoodCourt are zero, CryoSleep is almost certainly True. Build these dependency-aware imputers before throwing the data at the model.

The winning trick is target-encoding HomePlanet x Destination interactions and tuning num_leaves down to 31 with early stopping. A deep tabular net like TabNet or a CatBoost ensemble bumps you another 0.003. Pitfall — leaking group fate via aggregations on the full dataset; aggregate within fold.', 'AI/ML', 'beginner', 'Kaggle', 'Kaggle', NULL, 'https://www.kaggle.com/competitions/spaceship-titanic', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/spaceship-titanic/data","format":"csv"}]'::jsonb, '[{"label":"LightGBM docs","url":"https://lightgbm.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['python','lightgbm','tabular','feature-engineering','classification']::text[]),
  ('kaggle-bike-sharing-demand', 'Bike Sharing Demand', 'Forecast hourly bike rental counts in Washington DC''s Capital Bikeshare program using two years of historical usage joined with weather, season, and holiday signals. Submissions are scored on root mean squared logarithmic error.', 'Because the target is heavily right-skewed, model log1p(count) and invert at predict time — RMSLE collapses to plain RMSE on the logged target. Split count into casual + registered, model the two separately, then sum back; this two-headed approach was the trick that put the original top-100 leaderboard above 0.39.

Feature engineering wins this one. Extract hour, day-of-week, month, year, and crucially the hour x workingday interaction — commuters give a sharp 8 AM and 5 PM peak on weekdays that collapses on weekends. A Random Forest with 500 trees and depth 16 is the no-nonsense baseline; gradient boosting on the same features adds about 0.02 RMSLE.

Pitfall — temperature and feels-like-temperature are 0.98 correlated. Drop one or the trees will waste splits. Also windspeed has many zeros that are actually missing values; impute with knn on temp + humidity.', 'AI/ML', 'beginner', 'Kaggle', 'Kaggle', NULL, 'https://www.kaggle.com/competitions/bike-sharing-demand', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/bike-sharing-demand/data","format":"csv"}]'::jsonb, '[{"label":"scikit-learn ensembles","url":"https://scikit-learn.org/stable/modules/ensemble.html","kind":"docs"}]'::jsonb, ARRAY['python','regression','tabular','time-series','random-forest']::text[]),
  ('kaggle-dogs-vs-cats', 'Dogs vs. Cats', 'Binary image classification — distinguish photos of dogs from photos of cats across 25000 labelled training images. The 2013 competition that put deep CNNs on the data-science map and remains the canonical first transfer-learning project.', 'Skip writing a CNN from scratch — transfer learning from ImageNet weights crushes this. Load ResNet50 or EfficientNetB0 with include_top=False, freeze the backbone, add a GlobalAveragePooling2D plus Dense(1, sigmoid) head, train for 3 epochs at lr=1e-3, then unfreeze the top blocks and fine-tune at lr=1e-5. That alone hits 98 percent.

Resize to 224x224, normalize with the ImageNet mean and std, and use horizontal flip + slight rotation augmentation. Binary cross-entropy is the loss; Adam is the optimizer. The submission file is image-id plus probability — Kaggle scores with log loss so do NOT round to 0 or 1, clip predictions to [0.005, 0.995].

Pitfall — the directory layout dumps all 25000 images in one folder named like cat.0.jpg or dog.42.jpg. You have to parse the class from the filename before you can build a tf.data pipeline. The Redux variant uses log-loss explicitly; older copies of the comp used accuracy.', 'AI/ML', 'beginner', 'Kaggle', 'Kaggle', '2013', 'https://www.kaggle.com/competitions/dogs-vs-cats', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/dogs-vs-cats/data","format":"images"}]'::jsonb, '[{"label":"Keras transfer learning guide","url":"https://keras.io/guides/transfer_learning/","kind":"tutorial"}]'::jsonb, ARRAY['python','tensorflow','transfer-learning','cnn','computer-vision']::text[]),
  ('kaggle-home-credit-default-risk', 'Home Credit Default Risk', 'Predict whether a loan applicant will repay using application data plus joined tables of prior credit bureau records, previous loan history, and monthly payment behaviour. A classic large-scale tabular classification problem scored on ROC-AUC.', 'This is a multi-table competition — application_train is just the start. The seven auxiliary tables (bureau, bureau_balance, previous_application, POS_CASH_balance, installments_payments, credit_card_balance, application_test) must be aggregated per SK_ID_CURR and joined back. The classic public kernel by Aguiar produces about 700 engineered features this way.

LightGBM with categorical_feature support is the workhorse — handle missings natively, set num_leaves to 32, learning_rate to 0.02, and use 5-fold stratified CV with early stopping on AUC. The dataset is imbalanced — 8 percent default rate — but you should NOT oversample; LightGBM handles it via scale_pos_weight or just leaves the imbalance alone since AUC is rank-based.

Pitfall — DAYS_BIRTH and similar columns are negative integers (days before application). Convert to positive years. Also feature leakage is rampant if you compute aggregations on the train + test union without care; build the pipeline so test aggregations only use bureau and previous_application records dated before the application date.', 'AI/ML', 'intermediate', 'Home Credit Group', 'Kaggle', '2018', 'https://www.kaggle.com/competitions/home-credit-default-risk', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/home-credit-default-risk/data","format":"csv"}]'::jsonb, '[{"label":"LightGBM Python API","url":"https://lightgbm.readthedocs.io/en/latest/Python-API.html","kind":"docs"}]'::jsonb, ARRAY['python','lightgbm','tabular','credit-risk','feature-engineering']::text[]),
  ('kaggle-porto-seguro-safe-driver', 'Porto Seguro Safe Driver Prediction', 'Predict the probability a Brazilian auto insurance policyholder will file a claim in the next year. Features are anonymized into groups (ind, reg, car, calc) with -1 used as a missing-value sentinel. Scored on the normalized Gini coefficient.', 'Start with XGBoost or LightGBM — gradient boosting on the raw 57 anonymized features gets you to 0.282 Gini with 5-fold CV. Treat -1 as NaN before training so the tree learner can route missingness optimally rather than thinking -1 is a real value.

The winning approach mixed gradient boosting with a denoising autoencoder for feature representation, then trained a multi-layer perceptron on the bottleneck. Even without the autoencoder, target-encoding the high-cardinality categorical columns (ps_car_11_cat with 100+ categories) gives a measurable lift — use leave-one-out or k-fold target encoding to avoid leakage.

Pitfall — the calc_* features are pure noise. Drop them entirely or you waste model capacity. Also, the normalized Gini scoring rewards correct ranking, not calibrated probability, so do not optimize log-loss religiously — use the custom Gini eval metric for early stopping.', 'AI/ML', 'intermediate', 'Porto Seguro', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/porto-seguro-safe-driver-prediction', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/porto-seguro-safe-driver-prediction/data","format":"csv"}]'::jsonb, '[{"label":"XGBoost docs","url":"https://xgboost.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['python','xgboost','tabular','insurance','imbalanced']::text[]),
  ('kaggle-mercedes-benz-greener-manufacturing', 'Mercedes-Benz Greener Manufacturing', 'Predict how long a Mercedes-Benz car spends on the testing bench given a vector of 376 mostly-binary anonymized configuration features. Scored on R squared on the private leaderboard with a notoriously unstable public-private split.', 'The training set is tiny — 4209 rows and many duplicate feature vectors. Start by deduplicating. XGBoost with shallow trees (max_depth=4) and heavy regularization (reg_alpha=2, reg_lambda=2) is the right baseline; a deep model will memorize noise.

Dimensionality reduction helps. Run PCA, ICA, TruncatedSVD, and GaussianRandomProjection on the binary columns (12 components each was the canonical recipe), and concatenate the components onto the original features. Stack XGBoost + Lasso + a small ElasticNet for the final submission.

Pitfall — public-private leaderboard correlation is poor. Trust your cross-validation, not the public score. Outliers at y > 170 seconds will destroy R squared if a model overfits to them — winsorize the target or use Huber-style loss. Also the categorical X0-X8 columns need label encoding ordered by mean target.', 'AI/ML', 'intermediate', 'Mercedes-Benz', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/mercedes-benz-greener-manufacturing', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/mercedes-benz-greener-manufacturing/data","format":"csv"}]'::jsonb, '[{"label":"scikit-learn decomposition","url":"https://scikit-learn.org/stable/modules/decomposition.html","kind":"docs"}]'::jsonb, ARRAY['python','xgboost','tabular','regression','dimensionality-reduction']::text[]),
  ('kaggle-jigsaw-toxic-comment', 'Toxic Comment Classification Challenge', 'Multi-label NLP — given a Wikipedia talk-page comment, predict probabilities across six toxicity labels (toxic, severe_toxic, obscene, threat, insult, identity_hate). The launchpad competition for transformer-based content moderation work, scored on mean column-wise AUC.', 'A logistic regression on TF-IDF word + char n-grams is shockingly competitive — sklearn''s TfidfVectorizer with ngram_range=(1,2) on words and (2,6) on characters, then one-vs-rest LogisticRegression with C=4. That alone gets 0.984 AUC. Use sparse matrices throughout or memory blows up.

The modern way is to fine-tune a pretrained encoder — BERT-base or RoBERTa via Hugging Face transformers with a sigmoid head over 6 outputs and BCEWithLogitsLoss. Train two epochs, lr=2e-5, sequence length 220. That hits 0.989+.

Pitfall — labels are heavily imbalanced (threat is 0.3 percent positive). Do NOT use loss weighting; AUC is rank-based. Comments include heavy obfuscation (f@@k, sh1t, leet speak); the character n-gram features catch this where pure word models miss it. Clean too aggressively and you destroy the signal.', 'AI/ML', 'intermediate', 'Jigsaw (Google)', 'Kaggle', '2018', 'https://www.kaggle.com/competitions/jigsaw-toxic-comment-classification-challenge', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/jigsaw-toxic-comment-classification-challenge/data","format":"csv"}]'::jsonb, '[{"label":"Hugging Face transformers","url":"https://huggingface.co/docs/transformers/index","kind":"docs"}]'::jsonb, ARRAY['python','nlp','transformers','bert','multi-label']::text[]),
  ('kaggle-quora-question-pairs', 'Quora Question Pairs', 'Identify whether two Quora questions have the same meaning (duplicate detection). About 400k labelled question pairs, scored on log loss. The seminal Kaggle semantic similarity benchmark.', 'A magic baseline is engineering distance features — TF-IDF cosine similarity, character-level Jaccard, word-mover distance via gensim, fuzzywuzzy partial-ratio, and length-difference. Feed those into XGBoost and you land at about 0.30 log loss.

For a deep approach, use a siamese encoder — embed both questions with the same BiLSTM or pretrained BERT, then compute the elementwise diff and product, concatenate, and pass through an MLP. SBERT (sentence-transformers all-MiniLM-L6-v2) provides excellent embeddings out of the box and fine-tunes in minutes.

Pitfall — the famous Quora magic feature is graph leakage. If two questions share many common neighbours in the question-pair graph they tend to be duplicates. Top teams exploited this but it inflates performance because the test set leaks structure. Build a question-neighbour graph from train + test together for the leaderboard, but evaluate locally with strict question-disjoint folds.', 'AI/ML', 'intermediate', 'Quora', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/quora-question-pairs', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/quora-question-pairs/data","format":"csv"}]'::jsonb, '[{"label":"Sentence-transformers docs","url":"https://www.sbert.net/","kind":"docs"}]'::jsonb, ARRAY['python','nlp','siamese','sentence-embeddings','duplicate-detection']::text[]),
  ('kaggle-commonlit-readability', 'CommonLit Readability Prize', 'Predict the reading-difficulty score of short literary passages aimed at grades 3-12. About 2800 training excerpts with a continuous target measured by Bradley-Terry pairwise teacher ratings. Scored on RMSE.', 'Fine-tune RoBERTa-large with a regression head — pool the [CLS] hidden state through a small MLP and predict the float score. Use the Hugging Face Trainer with MSE loss, lr=2e-5, batch_size=8, 3 epochs. That alone clears the bronze threshold (RMSE around 0.475).

The winning teams averaged predictions across many RoBERTa, DeBERTa, and Electra checkpoints, each trained with different seeds and pooling strategies (attention pooling vs mean pooling vs concatenation of last-4 layers). Add stochastic weight averaging and a small amount of MLM continued pretraining on the raw passages first.

Pitfall — the standard_error column in train.csv is the rater-disagreement metric, NOT a feature; do not feed it in. Train set is small so single-fold training is noisy — use 5x5 nested CV. Length matters — pad/truncate to 256 tokens and you lose some long-passage signal; truncate to 384 for better RMSE.', 'AI/ML', 'intermediate', 'CommonLit & Georgia State', 'Kaggle', '2021', 'https://www.kaggle.com/competitions/commonlitreadabilityprize', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/commonlitreadabilityprize/data","format":"csv"}]'::jsonb, '[{"label":"Hugging Face Trainer","url":"https://huggingface.co/docs/transformers/main_classes/trainer","kind":"docs"}]'::jsonb, ARRAY['python','nlp','transformers','regression','roberta']::text[]),
  ('kaggle-feedback-prize-ell', 'Feedback Prize - English Language Learning', 'Score essays written by 8th-12th grade English Language Learners across six analytic measures (cohesion, syntax, vocabulary, phraseology, grammar, conventions) each scaled 1.0-5.0 in 0.5 increments. Scored on mean column-wise RMSE.', 'Multi-target regression on essay text. Fine-tune DeBERTa-v3-large with six regression outputs and MSE loss. Sequence length 1024 (essays are long), batch 4 with gradient accumulation, lr=1e-5, 3-5 epochs. Public baseline notebooks land around 0.45 RMSE.

The 1st place solution stacked DeBERTa-v3-large with adversarial weight perturbation (AWP), used attention-pooling instead of CLS, and added a LightGBM second stage that took the transformer logits plus hand-crafted essay-length and POS-ratio features. Smooth-L1 loss is slightly better than MSE on the 0.5-step ordinal targets.

Pitfall — the six targets are highly correlated (>0.6); train one multi-head model not six independent ones. Also do NOT label-smooth or round predictions to 0.5 increments; the metric rewards the continuous prediction. Some essays are nearly empty — clip predictions to the train target range or you get penalized hard for extrapolation.', 'AI/ML', 'advanced', 'The Learning Agency Lab', 'Kaggle', '2022', 'https://www.kaggle.com/competitions/feedback-prize-english-language-learning', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/feedback-prize-english-language-learning/data","format":"csv"}]'::jsonb, '[{"label":"DeBERTa paper","url":"https://arxiv.org/abs/2006.03654","kind":"paper"}]'::jsonb, ARRAY['python','nlp','deberta','regression','essay-scoring']::text[]),
  ('kaggle-store-sales-time-series', 'Store Sales - Time Series Forecasting', 'Forecast daily unit sales for thousands of product families across 54 Favorita grocery stores in Ecuador. Auxiliary tables include oil prices, holidays, store metadata, and transactions. The current canonical playground for hierarchical retail forecasting.', 'Treat each (store, family) pair as a series — about 1800 of them across 16 days of prediction. The reference baseline is a per-pair seasonal-naive plus an ML residual model. Use sklearn''s HistGradientBoostingRegressor on lag features (lag-1, lag-7, lag-14, lag-28) and rolling means; that wraps you into the top half.

LightGBM with global model architecture beats per-series models. Encode store_nbr and family as categorical, add date features (dayofweek, day-of-month, month, year), exogenous oil price, and a holiday flag with locale/national/regional distinction. Forecast log1p(sales) and clip negatives.

Pitfall — Ecuador had a strong 2016 earthquake that distorted weeks in April and May 2016. Either drop those weeks from training or add an earthquake-indicator. Also onpromotion is a leak-safe future-known signal (the competition gives it for the forecast horizon); use it. Many beginners ignore that column.', 'AI/ML', 'intermediate', 'Corporación Favorita', 'Kaggle', NULL, 'https://www.kaggle.com/competitions/store-sales-time-series-forecasting', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/store-sales-time-series-forecasting/data","format":"csv"}]'::jsonb, '[{"label":"Forecasting course","url":"https://www.kaggle.com/learn/time-series","kind":"tutorial"}]'::jsonb, ARRAY['python','lightgbm','time-series','forecasting','retail']::text[]),
  ('kaggle-m5-forecasting-accuracy', 'M5 Forecasting - Accuracy', 'Predict 28 days of daily unit sales for 30490 Walmart item-store series across California, Texas, and Wisconsin. The Makridakis M5 competition brought academic forecasting onto Kaggle and remains the gold standard hierarchical forecasting benchmark.', 'The competition is solved at the bottom level (item x store) — 30490 series — and aggregated implicitly through the WRMSSE metric. A single global LightGBM regressor on all series with categorical embeddings for item_id, dept_id, store_id, state_id is the workhorse. Generate lag features (lag 7, 14, 28) and rolling means (windows 7, 28).

The Kaggle winner (Yeonjun In) used a recursive LightGBM forecaster with non-overlapping training windows and a Tweedie loss to handle the heavy zero-inflation of grocery sales. SNAP food-stamp flags by state are highly predictive — keep them as binary features per state. CV by sliding 28-day windows; do not random-split.

Pitfall — data is in wide format (one row per item, columns d_1 to d_1941). Melt to long format BEFORE feature engineering or you will run out of RAM on Kaggle''s 16 GB instance. Use np.float32 dtypes and Polars or Vaex if pandas chokes.', 'AI/ML', 'advanced', 'University of Nicosia', 'Kaggle', '2020', 'https://www.kaggle.com/competitions/m5-forecasting-accuracy', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/m5-forecasting-accuracy/data","format":"csv"}]'::jsonb, '[{"label":"M5 paper","url":"https://arxiv.org/abs/2008.10866","kind":"paper"}]'::jsonb, ARRAY['python','lightgbm','time-series','hierarchical','tweedie']::text[]),
  ('kaggle-optiver-trading-at-the-close', 'Optiver - Trading at the Close', 'Predict 60-second future returns of 200 NASDAQ stocks during the closing-cross auction window using order-book imbalance and reference-price snapshots. A 100k-prize-pool quantitative-finance competition with a code-submission inference window.', 'The target is the 60-second-ahead return relative to a synthetic index — already de-meaned and de-volatilized, so you do not need to normalize it further. LightGBM on raw features (imbalance_size, reference_price, far_price, near_price, bid_price, ask_price, wap, and their interactions) crosses the gold-medal line with careful feature crafting.

Key engineered features — imbalance_buy_sell_flag x imbalance_size, log(bid_price/ask_price) bid-ask spread, wap-vs-reference deviation, and rolling features within the day''s 10-minute auction window grouped by stock_id. Time-of-day (seconds_in_bucket) is itself extremely predictive — auction dynamics shift sharply in the final 90 seconds.

Pitfall — the submission is a Kaggle API time-series API, not a CSV. You must run inference inside the provided generator under a 9-hour budget. Cache features incrementally; do not recompute from scratch each tick. Also stock_id 0-199 are individual tickers and stock-specific medians leak across the train/test split if you compute them on the full pooled set.', 'AI/ML', 'advanced', 'Optiver', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/optiver-trading-at-the-close', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/optiver-trading-at-the-close/data","format":"csv"}]'::jsonb, '[{"label":"Optiver write-up","url":"https://optiver.com/kaggle-and-optiver-predicting-nasdaqs-closing-cross-auction-movements/","kind":"docs"}]'::jsonb, ARRAY['python','finance','lightgbm','order-book','time-series']::text[]),
  ('kaggle-two-sigma-financial-modeling', 'Two Sigma Financial Modeling Challenge', 'Forecast intraday returns of anonymized financial instruments using 110 anonymized features. The first Kaggle code competition — submissions ran inside a sandboxed environment that streamed time steps one at a time, mirroring real-time prediction.', 'Treat this as a regression to predict y per (id, timestamp). Out of 110 features, only 30 carry signal; do feature selection by mutual information or Boruta first. A simple ridge regression of y on rolling-mean features per instrument is a respectable baseline (public R around 0.012).

Gradient boosting (XGBoost with very shallow trees, max_depth=4) on selected technical features wins. Add per-id grouped statistics — instrument volatility, recent return autocorrelation, etc. Keep the model SMALL; the API streams predictions and gives you only seconds per step.

Pitfall — the metric is a clipped R-squared style score sensitive to outliers; clip y at percentile 1 and 99 in training. The features fundamental_*, technical_*, derived_* are anonymized but technical_30 and technical_20 are the highest-signal ones in nearly every public kernel. Do not leak future timestamps when computing rolling means.', 'AI/ML', 'advanced', 'Two Sigma', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/two-sigma-financial-modeling', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/two-sigma-financial-modeling/data","format":"parquet"}]'::jsonb, '[{"label":"XGBoost params","url":"https://xgboost.readthedocs.io/en/stable/parameter.html","kind":"docs"}]'::jsonb, ARRAY['python','finance','xgboost','code-competition','regression']::text[]),
  ('kaggle-rsna-pneumonia-detection', 'RSNA Pneumonia Detection Challenge', 'Object-detection in chest X-rays — draw bounding boxes around lung opacities suspicious for pneumonia. 26684 frontal-view DICOM images from the Radiological Society of North America, scored on mean Average Precision at IoU thresholds 0.4-0.75.', 'DICOM is the gotcha — use pydicom to load, then rescale to 8-bit. Resize to 256x256 or 512x512. The task is two-stage in practice — first a binary classifier for pneumonia present/absent (ResNet50 backbone, BCE loss), then a detector (RetinaNet or Faster R-CNN from torchvision) on the positive subset to produce boxes.

A more direct approach is YOLOv5 or YOLOv8 trained directly on the bounding-box CSV. Convert Kaggle annotations (x, y, width, height in pixels) to YOLO format (cx, cy, w, h normalized). Train 50 epochs with image size 512, mosaic augmentation off (X-rays do not benefit from it).

Pitfall — the dataset has duplicate patients with multiple views; do GroupKFold by patientId or your CV is inflated. Also class_id labels include three classes (Normal, No Lung Opacity, Lung Opacity) — use that auxiliary information for multitask training, do not collapse to binary too early. Many opacities have very low confidence; post-process with NMS at IoU 0.4 and confidence around 0.2.', 'AI/ML', 'advanced', 'RSNA', 'Kaggle', '2018', 'https://www.kaggle.com/competitions/rsna-pneumonia-detection-challenge', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/rsna-pneumonia-detection-challenge/data","format":"images"}]'::jsonb, '[{"label":"torchvision detection","url":"https://pytorch.org/vision/stable/models.html#object-detection","kind":"docs"}]'::jsonb, ARRAY['python','pytorch','object-detection','medical-imaging','dicom']::text[]),
  ('kaggle-histopathologic-cancer-detection', 'Histopathologic Cancer Detection', 'Binary classification of 96x96 patches extracted from gigapixel whole-slide images — does the center 32x32 region contain tumor tissue? Based on the PatchCamelyon (PCam) benchmark. 220000 training patches scored on ROC-AUC.', 'Patches are small — a from-scratch DenseNet121 or EfficientNet-B0 at 96x96 trains fast and reaches AUC 0.97 in 10 epochs on a single GPU. Use stain-aware augmentation (Macenko or Reinhard color normalization) plus horizontal/vertical flips and 90-degree rotations — histology has rotational symmetry, so include all 8 D4 symmetries.

Binary cross-entropy, Adam at lr=1e-3 with ReduceLROnPlateau. Test-time augmentation (TTA) over the 8 symmetries averages out flips and bumps you about 0.005 AUC. Public-private split is well-correlated so trust local 5-fold CV.

Pitfall — the dataset is balanced (60/40) but the 32x32 center-pixel rule means a tumor cell at the patch edge is labelled negative. Cropping inputs to the center 64x64 sometimes outperforms training on the full 96x96. Also do not normalize using ImageNet stats — compute and apply the PCam-specific mean/std (about 0.70, 0.55, 0.69 for RGB).', 'AI/ML', 'intermediate', 'PCam / Camelyon', 'Kaggle', '2019', 'https://www.kaggle.com/competitions/histopathologic-cancer-detection', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/histopathologic-cancer-detection/data","format":"images"}]'::jsonb, '[{"label":"PCam paper","url":"https://arxiv.org/abs/1806.03962","kind":"paper"}]'::jsonb, ARRAY['python','pytorch','medical-imaging','cnn','histology']::text[]),
  ('kaggle-planet-amazon-from-space', 'Planet: Understanding the Amazon from Space', 'Multi-label classification of 256x256 4-band satellite chips from Planet Labs over the Amazon basin. Predict 17 labels covering atmospheric conditions (clear, haze, cloudy, partly cloudy) and land use (rainforest, agriculture, water, roads, etc.). Scored on mean F2.', 'Per-class threshold tuning is the single biggest lever. Train a ResNet50 or DenseNet121 with sigmoid head and BCE loss, then sweep per-label thresholds on validation to maximize F2 (which over-weights recall). A single threshold of 0.2 is the public-notebook baseline; per-label optimal thresholds add about 0.01 F2.

The chips come in both JPG and TIF — the 4-band TIF (RGB + near-infrared) carries extra signal for agriculture vs forest. Stack the NIR as a 4th channel into a modified-input ResNet, or compute NDVI = (NIR-R)/(NIR+R) and pass as an extra channel. Augment with rotations 0/90/180/270 and flips — clouds and forests are rotation-invariant.

Pitfall — the labels are correlated (cloudy implies no land-cover labels). Use a chained or hierarchical loss — first the atmospheric label, then land-cover only if not cloudy. Class imbalance is severe (slash_burn appears in only 0.5 percent of chips); use weighted BCE or focal loss for those rare labels.', 'AI/ML', 'intermediate', 'Planet', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/planet-understanding-the-amazon-from-space', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/planet-understanding-the-amazon-from-space/data","format":"images"}]'::jsonb, '[{"label":"Planet API docs","url":"https://developers.planet.com/","kind":"docs"}]'::jsonb, ARRAY['python','pytorch','satellite','multi-label','remote-sensing']::text[]),
  ('kaggle-understanding-cloud-organization', 'Understanding Clouds from Satellite Images', 'Semantic segmentation of NASA Worldview true-color satellite tiles into four cloud-organization classes (Sugar, Flower, Fish, Gravel). Scored on mean Dice coefficient over the four channels. A Max Planck climate-science collaboration.', 'U-Net with an EfficientNet-B2 encoder via segmentation-models-pytorch is the gold-standard architecture. Resize images to 384x576 (preserves the 1400x2100 aspect ratio at 1/3.6), use 4-channel output with sigmoid, BCE + Dice loss combo (alpha=0.5).

The four cloud classes overlap heavily — a single pixel can be both Fish and Gravel. Treat as multi-label segmentation (four independent sigmoid masks) rather than mutually-exclusive multiclass. Post-process by removing predicted masks smaller than a per-class area threshold (about 10000 px for Fish, 7500 for Sugar) — empty submissions for those classes outscore tiny noisy masks.

Pitfall — many images have NO label for some classes; respect that. RLE-decode/encode masks carefully — Kaggle uses one-based, column-major (Fortran) order. Also classifier-as-gate trick: train a multi-label image classifier in parallel; if the classifier says class is absent, zero out that segmentation channel entirely. That single trick added gold-medal points.', 'AI/ML', 'advanced', 'Max Planck Institute', 'Kaggle', '2019', 'https://www.kaggle.com/competitions/understanding_cloud_organization', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/understanding_cloud_organization/data","format":"images"}]'::jsonb, '[{"label":"segmentation-models-pytorch","url":"https://github.com/qubvel/segmentation_models.pytorch","kind":"repo"}]'::jsonb, ARRAY['python','pytorch','segmentation','satellite','u-net']::text[]),
  ('kaggle-carvana-image-masking', 'Carvana Image Masking Challenge', 'Binary semantic segmentation — produce a precise foreground mask separating a car from its studio background across 16-view-per-vehicle 1918x1280 photos. Scored on Dice coefficient. The de-facto U-Net benchmark.', 'U-Net is the right architecture, but resolution matters — train at 1024x1024 minimum or you lose the wheel-spoke edges. Use a pretrained encoder (ResNet34 or EfficientNet-B0) via segmentation-models-pytorch. Loss = BCE + Dice combined (Dice alone is unstable early).

Augmentation is light — horizontal flip plus a small shift/scale/rotate (5 percent). Cars are constrained in pose so heavy augmentation hurts. Test-time augmentation with horizontal flip gives a free 0.001 Dice. Train two stages — first at 512x512 for fast convergence, then resume at 1024x1024 for refinement.

Pitfall — submissions are RLE-encoded full-resolution (1918x1280) masks; do not downsample your output. Upsample with bilinear then threshold at 0.5. Edge artifacts around the antenna and wheel rims dominate the residual error — boundary loss (Lovasz-hinge) on top of Dice nudges those pixels. Also the same car appears across 16 angles; GroupKFold by car-id, not random split.', 'AI/ML', 'intermediate', 'Carvana', 'Kaggle', '2017', 'https://www.kaggle.com/competitions/carvana-image-masking-challenge', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/carvana-image-masking-challenge/data","format":"images"}]'::jsonb, '[{"label":"U-Net paper","url":"https://arxiv.org/abs/1505.04597","kind":"paper"}]'::jsonb, ARRAY['python','pytorch','segmentation','u-net','computer-vision']::text[]),
  ('kaggle-plant-pathology-2021', 'Plant Pathology 2021 - FGVC8', 'Fine-grained multi-label classification of apple-leaf foliar diseases — apple scab, cedar apple rust, frog eye leaf spot, powdery mildew, complex (multi-disease), and healthy. Part of the FGVC workshop at CVPR. Scored on mean F1.', 'Transfer learning from ImageNet with EfficientNet-B3 or B4 at 512x512 resolution. Multi-label sigmoid head with BCEWithLogitsLoss because the complex class signals co-occurrence of multiple labels. Train 20 epochs with cosine LR schedule, lr=1e-3 with AdamW.

Label noise is the dominant problem — about 8 percent of training labels are wrong (FGVC organizers acknowledged this). Use label smoothing (0.05), MixUp augmentation, and noisy-student-style pseudo-labelling on test images. A two-stage train-then-correct approach (train, predict on noisy train, drop disagreements, retrain) consistently helps.

Pitfall — the dataset is small (about 18000 images) and FGVC tests on out-of-distribution sites. Heavy augmentation (RandAugment with magnitude 9, plus CutMix) is essential; without it you overfit to studio backgrounds. Also classes are imbalanced — frog_eye_leaf_spot is 30 percent of data, complex is under 8 percent. Weighted random sampling rather than weighted loss.', 'AI/ML', 'intermediate', 'FGVC8 / Cornell', 'Kaggle', '2021', 'https://www.kaggle.com/competitions/plant-pathology-2021-fgvc8', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/plant-pathology-2021-fgvc8/data","format":"images"}]'::jsonb, '[{"label":"timm models","url":"https://github.com/huggingface/pytorch-image-models","kind":"repo"}]'::jsonb, ARRAY['python','pytorch','fgvc','agriculture','multi-label']::text[]),
  ('kaggle-bengaliai-cv19', 'Bengali.AI Handwritten Grapheme Classification', 'Decompose handwritten Bengali graphemes into three components — grapheme root (168 classes), vowel diacritic (11), consonant diacritic (7). About 200000 137x236 grayscale samples. Scored on hierarchical macro-recall.', 'Three-head multitask CNN. Use an EfficientNet or SE-ResNeXt backbone with three parallel classifier heads — one CrossEntropy loss per head, summed with equal weights. Resize to 128x128 or 137x236, train with heavy CutMix and MixUp.

The hierarchical macro-recall scoring weights the root component twice, so weight root loss 2x in the multitask sum. Pseudo-label the test set after a first round; many test combinations of (root, vowel, consonant) never appear in training so the model must generalize compositionally — the winning solution explicitly used a generative ArcFace head to push apart same-root different-diacritic embeddings.

Pitfall — the parquet files store flattened pixel arrays; reshape correctly to (137, 236) not (236, 137) or your characters are sideways. Also out-of-distribution generalisation matters more than train accuracy — many top public-leaderboard models crashed on private because the private set used unseen grapheme combinations. CV by held-out root x vowel groups, not random split.', 'AI/ML', 'advanced', 'Bengali.AI', 'Kaggle', '2020', 'https://www.kaggle.com/competitions/bengaliai-cv19', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/bengaliai-cv19/data","format":"parquet"}]'::jsonb, '[{"label":"ArcFace paper","url":"https://arxiv.org/abs/1801.07698","kind":"paper"}]'::jsonb, ARRAY['python','pytorch','multitask','cnn','ocr']::text[]),
  ('kaggle-birdclef-2024', 'BirdCLEF 2024', 'Audio classification — identify bird, amphibian, mammal, and insect species from short clips recorded across the Western Ghats of India. About 180 target species across hours of soundscape audio. Scored on macro-averaged area under the ROC.', 'Convert audio to mel-spectrograms with librosa — 128 mel bins, hop_length=512, sample_rate=32000. Treat the spectrogram as an image and train an EfficientNet-B0 or AST (Audio Spectrogram Transformer) with sigmoid multi-label head and BCE loss. Crop 5-second windows during training, average windows during inference.

The canonical augmentation stack is SpecAugment (time and frequency masks), random gain, and background-noise mixup from the soundscape/no-call clips provided by Kaggle. Pretrain on prior years'' BirdCLEF labelled clips — there is huge transferable signal across years.

Pitfall — train is weakly-labelled (one species per file, may contain many) and test is strongly-labelled (per-5-second window). Treat training labels as primary plus secondary_labels and feed both as positives. The submission file is a one-row-per-clip-per-species-per-5-second-row; do NOT thresholds — submit raw probabilities. Inference must run inside Kaggle in under 9 hours on a CPU-only kernel; convert your model to ONNX or use torch.jit and quantize to int8.', 'AI/ML', 'advanced', 'Cornell Lab of Ornithology', 'Kaggle', '2024', 'https://www.kaggle.com/competitions/birdclef-2024', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/birdclef-2024/data","format":"audio"}]'::jsonb, '[{"label":"librosa docs","url":"https://librosa.org/doc/latest/index.html","kind":"docs"}]'::jsonb, ARRAY['python','pytorch','audio','spectrogram','bioacoustics']::text[]),
  ('kaggle-otto-recommender-system', 'OTTO - Multi-Objective Recommender System', 'Session-based e-commerce recommender — given a sequence of click/cart/order events within a session, predict the next 20 likely clicks, the next 20 carts, and the next 20 orders. Two months of real OTTO Germany sessions, scored on weighted Recall@20.', 'Two-stage retrieve-and-rerank is mandatory at this scale (12 million sessions, 1.8 million products). Stage 1 — candidate generation via co-visitation matrices (computed by counting how often item A and item B appear in the same session) plus Word2Vec item embeddings over click sequences (gensim or implicit). Take top 100 candidates per session.

Stage 2 — rerank with LightGBM ranker (LambdaRank objective) using features like co-visitation score, recency of last interaction, item popularity in the past 1-day/1-hour, and embedding cosine similarity. Train one ranker per target type (clicks, carts, orders) since their behavior differs.

Pitfall — data is HUGE (10+ GB of parquet). Use Polars or RAPIDS cuDF; pandas will OOM. The evaluation metric weights orders 0.6, carts 0.3, clicks 0.1, so put your engineering budget on the order model. Also avoid recommending items the user already ordered in the same session; many naive recommenders waste slots on duplicates.', 'AI/ML', 'advanced', 'OTTO', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/otto-recommender-system', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/otto-recommender-system/data","format":"parquet"}]'::jsonb, '[{"label":"RAPIDS Merlin","url":"https://github.com/NVIDIA-Merlin","kind":"repo"}]'::jsonb, ARRAY['python','recommender','lightgbm','session-based','ranking']::text[]),
  ('kaggle-shopee-product-matching', 'Shopee - Price Match Guarantee', 'Multimodal product-matching — identify which Shopee product listings refer to the same physical product across about 34000 train images plus titles. Output groups of duplicate posting_ids. Scored on mean F1.', 'Two parallel encoders — an EfficientNet-B3 image encoder fine-tuned with ArcFace metric loss, and a multilingual BERT (xlm-roberta-base or sentence-transformers paraphrase-multilingual-MiniLM) text encoder. Concatenate the L2-normalized embeddings, then do approximate-nearest-neighbour search with FAISS at inference.

Key trick — threshold the cosine similarity adaptively per query rather than using a single global threshold. Also union the matches from image-only, text-only, and concatenated embeddings — each captures slightly different duplicates. The competition titles are in Indonesian/Malay/English mixed; xlm-roberta handles all three well.

Pitfall — phash (perceptual hash) provided in the data IS a strong feature; do not ignore it. The metric is mean F1 over per-row matches and many beginners report only the top-K matches, missing the full set when a product has many duplicates. Submit ALL items above the threshold. CV by label_group (ground-truth duplicate cluster) so the same duplicate group is never split across folds.', 'AI/ML', 'advanced', 'Shopee', 'Kaggle', '2021', 'https://www.kaggle.com/competitions/shopee-product-matching', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/shopee-product-matching/data","format":"images"}]'::jsonb, '[{"label":"ArcFace + Faiss","url":"https://github.com/facebookresearch/faiss","kind":"repo"}]'::jsonb, ARRAY['python','pytorch','multimodal','arcface','metric-learning']::text[]),
  ('kaggle-image-matching-2024', 'Image Matching Challenge 2024 - Hexathlon', 'Reconstruct 3D scene structure from unstructured photo collections across six diverse domains (transparent, symmetric, repetitive, historical, low-texture, and aerial scenes). Scored on the mean Average Accuracy of estimated camera poses.', 'The workflow is pairs-then-poses. (1) Find image pairs likely to overlap — use NetVLAD or DINOv2 global descriptors plus nearest-neighbour retrieval. (2) Extract local features — SuperPoint or DISK keypoints. (3) Match them — LightGlue or SuperGlue. (4) Run COLMAP or hloc to do incremental Structure-from-Motion and recover camera poses.

hloc (Hierarchical-Localization) packages the whole pipeline end-to-end; start there. The 2024 Hexathlon penalty for the symmetric/transparent scenes can be reduced by rotation-aware descriptors — DINOv2 frozen features as a fallback for the hard scenes are surprisingly strong because they encode object-level not patch-level cues.

Pitfall — submissions are camera-pose CSVs (rotation matrix + translation per image) referenced to an arbitrary world frame; the metric is gauge-invariant, but you must NOT submit identity rotations as a default. Many domains have very few overlapping pairs — retrieval recall is the bottleneck, not matching precision. Tune the pairs-per-image down to 30-50 to keep COLMAP under the 9-hour Kaggle budget.', 'AI/ML', 'advanced', 'Google Research / CVPR IMW', 'Kaggle', '2024', 'https://www.kaggle.com/competitions/image-matching-challenge-2024', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/image-matching-challenge-2024/data","format":"images"}]'::jsonb, '[{"label":"hloc toolbox","url":"https://github.com/cvg/Hierarchical-Localization","kind":"repo"}]'::jsonb, ARRAY['python','computer-vision','sfm','3d-reconstruction','colmap']::text[]),
  ('kaggle-ventilator-pressure-prediction', 'Google Brain - Ventilator Pressure Prediction', 'Predict the airway pressure waveform of a mechanically-ventilated sedated patient given a time series of control inputs (u_in, u_out) and lung physical attributes (R, C). Sequence-to-sequence regression scored on mean absolute error.', 'Bidirectional LSTM stack — 4 layers of biLSTM with hidden 256, predicting per-timestep pressure. Each breath is exactly 80 timesteps so no padding needed; just batch (B, 80, num_features). Add a small MLP head and use MAE loss directly.

Feature engineering for sequences — for each timestep add cumulative-sum of u_in, lag features (u_in at t-1, t-2), and u_in * (R, C) interactions. Encode R and C as categorical embeddings (they take small discrete sets). Add a global stat per breath as a broadcast feature.

Pitfall — the metric only scores timesteps where u_out is 0 (the inspiratory phase). Mask the loss accordingly during training — many beginners average over all 80 timesteps and waste model capacity on expiratory phase. Also stacked-LSTM with simple weighted average across many seeds and folds is the bronze-zone trick; transformers slightly underperform LSTMs here because the sequences are short and physics-driven.', 'AI/ML', 'intermediate', 'Google Brain', 'Kaggle', '2021', 'https://www.kaggle.com/competitions/ventilator-pressure-prediction', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/ventilator-pressure-prediction/data","format":"csv"}]'::jsonb, '[{"label":"PyTorch LSTM","url":"https://pytorch.org/docs/stable/generated/torch.nn.LSTM.html","kind":"docs"}]'::jsonb, ARRAY['python','pytorch','lstm','time-series','medical']::text[]),
  ('kaggle-g2net-gravitational-waves', 'G2Net Detecting Continuous Gravitational Waves', 'Detect simulated continuous gravitational-wave signals embedded in noisy LIGO Hanford and Livingston spectrograms. Signal-to-noise ratios are extremely low. Scored on ROC-AUC.', 'The data is already provided as SFT (Short-Fourier-Transform) HDF5 files — basically time-frequency complex spectrograms. Take the magnitude, log-scale it, and treat as an image. EfficientNet-B0 or a small ViT trained at 360x360 (cropped) gets you into the medal zone.

The trick — stack the two detectors as 2-channel input, and include power-line subtraction (notch filter at 50/60 Hz) before training. Augmentation is mostly negative — random time shifts work, but flipping does not (signals have temporal direction). Synthesise additional positive examples by injecting your own LALSuite continuous-wave signals into the noise files.

Pitfall — the public test set distribution differs from the private (different signal frequencies and SNRs). Your CV must use the FULL frequency band, not just train-set distributions, or you overfit to easy SNRs. AUC is highly sensitive to a few hard examples; ensemble many seeds with rank-averaging rather than probability-averaging.', 'AI/ML', 'advanced', 'G2Net (LIGO/Virgo)', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/g2net-detecting-continuous-gravitational-waves', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/g2net-detecting-continuous-gravitational-waves/data","format":"parquet"}]'::jsonb, '[{"label":"LALSuite","url":"https://lscsoft.docs.ligo.org/lalsuite/","kind":"docs"}]'::jsonb, ARRAY['python','physics','signal-processing','cnn','spectrogram']::text[]),
  ('kaggle-lanl-earthquake-prediction', 'LANL Earthquake Prediction', 'Predict time_to_failure for a laboratory earthquake from 150000-sample windows of raw acoustic emission signals. Single-feature signal regression scored on mean absolute error.', 'Hand-crafted statistical features beat raw signal CNN here. From each 150k window compute mean, std, skew, kurtosis, max, min, quantiles (5/25/50/75/95), spectral statistics (FFT mean/std), Hilbert envelope mean, and rolling-window kurtosis. About 100 numerical features fed to LightGBM gives a competitive baseline (MAE around 2.0).

The winning solution by Philipp Singer used a CatBoost model on engineered features PLUS the median of test-set predictions as a leakage adjustment — public/private test were segmented and shared statistics. For a clean modelling approach, train a 1D CNN (4 conv layers + global pooling) on the raw signal as a complement and ensemble with the GBM.

Pitfall — train.csv is a SINGLE long continuous time series; test files are independent segments. Naive random K-fold leaks because consecutive windows are correlated. Use GroupKFold by earthquake cycle (split at each failure). Also do not feed time_to_failure target leak — drop the rolling mean of the target accidentally being in your features.', 'AI/ML', 'intermediate', 'Los Alamos National Lab', 'Kaggle', '2019', 'https://www.kaggle.com/competitions/LANL-Earthquake-Prediction', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/LANL-Earthquake-Prediction/data","format":"csv"}]'::jsonb, '[{"label":"CatBoost docs","url":"https://catboost.ai/en/docs/","kind":"docs"}]'::jsonb, ARRAY['python','catboost','signal-processing','geophysics','time-series']::text[]),
  ('kaggle-talkingdata-adtracking', 'TalkingData AdTracking Fraud Detection Challenge', 'Predict whether a mobile-app click will lead to an app download — fraud detection at advertising scale (200 million clicks across 4 days, billions of label-zero examples). Scored on ROC-AUC.', 'This is a memory and speed problem before it is a modeling problem. Read the CSV with dtype={ip:uint32, app:uint16, device:uint16, os:uint16, channel:uint16} and parse click_time only when needed. LightGBM trains on the full 184M-row training set in under 30 minutes on a 32 GB machine if you keep dtypes tight.

Feature engineering — count and unique-count aggregations are the bread and butter. ip-day-hour click count, ip-app count, ip-device-os next-click-delta (seconds until same ip''s next click), and most importantly nextClick delta — the time gap to the next click from the same ip. The 1st-place team''s key feature was the delta to the NEXT click, not the previous.

Pitfall — the public test set is from day 4; train days 6-9 and validate on day 9 last 6 hours to mimic the temporal gap. Random K-fold gives wildly optimistic scores. Also do NOT use is_attributed in any aggregation — you will leak the target via ip-level rates.', 'AI/ML', 'intermediate', 'TalkingData', 'Kaggle', '2018', 'https://www.kaggle.com/competitions/talkingdata-adtracking-fraud-detection', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/talkingdata-adtracking-fraud-detection/data","format":"csv"}]'::jsonb, '[{"label":"LightGBM tuning","url":"https://lightgbm.readthedocs.io/en/latest/Parameters-Tuning.html","kind":"docs"}]'::jsonb, ARRAY['python','lightgbm','tabular','fraud','imbalanced']::text[]),
  ('kaggle-microsoft-malware-classification', 'Microsoft Malware Classification Challenge (BIG 2015)', 'Classify Windows malware binaries into 9 families given disassembled .asm files and raw .bytes hex dumps. About 21000 training samples (half a terabyte of disassembly). Scored on multiclass log loss.', 'Two parallel pipelines on the .bytes and .asm files, then ensemble. From .bytes — compute byte n-gram histograms (n=1, 2, 3) and treat the bytes as a flat grayscale image to feed into a small CNN. From .asm — count opcode mnemonics, section names, function call patterns, and string entropy. Concatenate features and train XGBoost on the union.

For a deep approach, the malware-as-image technique (reshape the bytes to a 2D image and run ResNet) is surprisingly competitive — Nataraj''s 2011 paper is the reference. Combine with opcode tf-idf features for the ensemble.

Pitfall — files range from kilobytes to 100+ MB; truncate or stride-sample uniformly when computing histograms or you bias toward small samples. Class 5 (Simda) has only 42 examples; use stratified K-fold and class weighting in log loss. Also the public-private split crosses different malware family proportions — heavy regularization (XGBoost reg_lambda=10) prevents private-leaderboard collapse.', 'AI/ML', 'advanced', 'Microsoft', 'Kaggle', '2015', 'https://www.kaggle.com/competitions/malware-classification', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/malware-classification/data","format":"binary"}]'::jsonb, '[{"label":"Malware-as-image paper","url":"https://arxiv.org/abs/1802.10135","kind":"paper"}]'::jsonb, ARRAY['python','xgboost','security','malware','n-gram']::text[]),
  ('kaggle-stanford-ribonanza-rna-folding', 'Stanford Ribonanza RNA Folding', 'Predict per-nucleotide chemical reactivity of RNA sequences to two probes (DMS, 2A3), which encode local structural state. Inputs are sequences up to 457 nt long. Scored on mean column-wise MAE.', 'Treat the RNA sequence as a token sequence and use a Transformer with rotary or ALiBi positional encoding. Vocabulary is small (A, C, G, U, plus special tokens). Predict two regression outputs per position. The public reference solution (squeezeformer-like with 12 transformer layers, hidden 192) trains in 6 hours on a single GPU.

The secret sauce is incorporating predicted secondary-structure as input — run EternaFold or RNAfold on each sequence to get base-pairing probability matrices and add them as a 2D attention bias to the transformer. The top teams (yu4u et al) used Squeezeformer or BPP-matrix-conditioned 2D-CNN-Transformer hybrids.

Pitfall — many positions are unreliable (low SNR signal_to_noise column). Filter training to SN_filter == 1 OR weight the loss by signal_to_noise per position. Also the test set contains longer sequences (Future test up to 457 nt) than train (max 206 nt); pretrain with random shorter crops and fine-tune longer — many top notebooks missed this and overfit to short sequences.', 'AI/ML', 'advanced', 'Stanford / Eterna', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/stanford-ribonanza-rna-folding', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/stanford-ribonanza-rna-folding/data","format":"parquet"}]'::jsonb, '[{"label":"EternaFold","url":"https://github.com/eternagame/EternaFold","kind":"repo"}]'::jsonb, ARRAY['python','pytorch','transformer','rna','bioinformatics']::text[]),
  ('kaggle-lux-ai-season-2', 'Lux AI Season 2', 'Build an agent that plays 1v1 in a multi-step resource-gathering game — collect ice, water, build factories and robots, and contest a Martian map against an opponent. Simulation environment, hidden test bots, scored by ELO across head-to-head matches.', 'Heuristic rule-based agents reach top 30 percent — start there before training anything. The Python kit ships with an agent.py that observes the JSON state and returns a Python dict of unit actions. Implement greedy logic — units pursue nearest ice tile, factories build a robot when energy is plentiful — and you have a working submission.

For learning-based, the standard approach is imitation learning from top public replays (download via the Kaggle API) followed by self-play with PPO from CleanRL or stable-baselines3. The observation space must be flattened to a fixed-size tensor per unit-or-factory; multi-agent shared policy with action masking is the standard pattern.

Pitfall — agents have a 9-second per-step compute budget and a 3-second startup; pure Python often busts the budget when the map gets full. Vectorize with numpy or jit with numba. Also you only submit once and your agent plays asynchronously against the entire ladder — bugs that crash on one map kind silently lose ELO. Test on the full set of map sizes the env supports.', 'AI/ML', 'advanced', 'Lux AI Challenge', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/lux-ai-season-2', '[{"label":"Game engine + starter kit","url":"https://www.kaggle.com/competitions/lux-ai-season-2/data","format":"code"}]'::jsonb, '[{"label":"CleanRL PPO","url":"https://github.com/vwxyzjn/cleanrl","kind":"repo"}]'::jsonb, ARRAY['python','reinforcement-learning','multi-agent','self-play','ppo']::text[]),
  ('kaggle-connectx', 'ConnectX', 'Always-on Kaggle Simulations competition — write an agent that plays generalized Connect-Four on configurable boards against other submitted agents. Continuous leaderboard scored by ELO.', 'On default 6x7 4-in-a-row, Connect-Four is a solved game — first player wins with perfect play. Implementing a minimax with alpha-beta pruning to depth 8-10 in Python already lands top 50. Use bitboards (each column as bits in a uint64) for 100x speedup over 2D arrays.

For general board sizes, MCTS with a small neural-network policy/value head trained via self-play (AlphaZero-style) is the principled path; libraries like OpenSpiel ship Connect-Four reference implementations. The agent must return one integer (the column to drop) in under 2 seconds per move.

Pitfall — your agent is wrapped in kaggle_environments and runs in a subprocess with limited stdout. Print statements can crash submissions. Also Kaggle''s matchmaking pairs you with weak bots until your ELO rises; do not panic if your first 30 games are flat — wait for the system to find peers. Cache opening books for the standard 6x7 to win first-move-decided games instantly.', 'AI/ML', 'beginner', 'Kaggle', 'Kaggle', NULL, 'https://www.kaggle.com/competitions/connectx', '[{"label":"Environment + starter","url":"https://www.kaggle.com/competitions/connectx/data","format":"code"}]'::jsonb, '[{"label":"OpenSpiel","url":"https://github.com/deepmind/open_spiel","kind":"repo"}]'::jsonb, ARRAY['python','reinforcement-learning','minimax','mcts','game-ai']::text[]),
  ('kaggle-santa-2023-polytope', 'Santa 2023 - The Polytope Permutation Puzzle', 'Solve a battery of permutation puzzles (Rubik''s cube variants, globe puzzles, wreath puzzles) — find the shortest sequence of allowed moves from a scrambled state to a solved state. Scored on total move count across all puzzles, lower is better.', 'Pure combinatorial optimization — no neural networks required to medal. For Rubik''s-cube-family puzzles, plug in an existing solver — kociemba (3x3) or rubikscubeNNN for higher orders — and you get near-optimal solutions out of the box. For globe and wreath puzzles, IDA* search with a permutation-pattern-database heuristic is the canonical approach.

Wrap the moves in the format Kaggle expects (a dot-separated string of allowed move names). For very large state spaces, bidirectional BFS from solved and scrambled meeting in the middle finds shorter paths than naive forward search. Pre-compute all single-move permutations as numpy index arrays once, then state-transition is a vectorized lookup.

Pitfall — the puzzles allow a small wildcards (you may leave a few positions wrong); exploit that to dramatically shorten solutions for the larger cubes. Also the moves dictionary in puzzle_info.csv encodes each move as a permutation list — parse it carefully; the inverse moves are NOT automatically included and must be derived. Brute-force RL with PPO is far too slow here; search-based methods dominate the leaderboard.', 'AI/ML', 'advanced', 'Kaggle', 'Kaggle', '2023', 'https://www.kaggle.com/competitions/santa-2023', '[{"label":"Competition dataset","url":"https://www.kaggle.com/competitions/santa-2023/data","format":"csv"}]'::jsonb, '[{"label":"kociemba solver","url":"https://github.com/hkociemba/RubiksCube-TwophaseSolver","kind":"repo"}]'::jsonb, ARRAY['python','optimization','search','combinatorial','ida-star']::text[]),
  ('kaggle-google-universal-image-embedding', 'Google Universal Image Embedding', 'Produce 64-dimensional image embeddings that work universally across diverse visual domains (apparel, artwork, packaged goods, landmarks, dishes, memes, storefronts). No training data is given by Kaggle — bring your own. Scored on mean Average Precision @ 5 over a hidden retrieval test set.', 'There is no training set in the competition — assemble your own from public sources. The 1st-place team combined Products-10K, Stanford Online Products, GLDv2, DeepFashion, MET Artworks, Alibaba goods, H&M, Shopee, GPR1200, and Food-101. Train a single backbone (CLIP ViT-L/14 finetuned, or BEiT-large) with ArcFace head and dynamic margin per class.

Project the backbone''s native output (e.g., 1024-d for ViT-L) down to 64-d via a learned linear layer with L2 normalization on the output — that 64-d constraint is the binding architectural choice. Train with a large batch (>512) and many classes (>200000) for effective contrastive learning.

Pitfall — the submission is a model file, not embeddings; Kaggle runs your inference pipeline on its hidden test set in under 9 hours on a P100 GPU. Optimize for inference speed — channels_last, float16, and pre-resize images to 224x224. Also the test domain mix is unknown; do not over-specialize on a single domain or you tank on the others.', 'AI/ML', 'advanced', 'Google Research', 'Kaggle', '2022', 'https://www.kaggle.com/competitions/google-universal-image-embedding', '[{"label":"Competition (BYO data)","url":"https://www.kaggle.com/competitions/google-universal-image-embedding/data","format":"code"}]'::jsonb, '[{"label":"OpenCLIP","url":"https://github.com/mlfoundations/open_clip","kind":"repo"}]'::jsonb, ARRAY['python','pytorch','metric-learning','embeddings','retrieval']::text[]),
  ('ethindia-base-consumer-apps', 'Base — Build Innovative Consumer Apps on Base', 'Coinbase''s Base L2 sponsor track at ETHIndia 2024 offering 11,500 USD for consumer-focused onchain apps. Teams ship a polished mobile-first dapp on Base that real users would actually want to use.', 'Install the Base development stack — Foundry or Hardhat for contracts, OnchainKit for the React frontend, and Coinbase Smart Wallet for keyless onboarding. Use the official base-org/onchainkit-template to scaffold a Next.js app with wallet connect, embedded fiat onramp, and gasless transactions wired in.

Pick a consumer use case that does not look like a generic DeFi dashboard — examples include onchain social, mini-games, tipping rails, ticketing, or creator monetisation. Deploy your contracts to Base Sepolia first, hook up Basenames for human-readable identity, and use Paymaster sponsorship so first-time users never see a gas prompt. Record a 60-second demo emphasizing the user journey, not the contract code.', 'Web3', 'intermediate', 'Coinbase / Base', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"Base docs","url":"https://docs.base.org/","kind":"docs"},{"label":"OnchainKit","url":"https://onchainkit.xyz/","kind":"docs"}]'::jsonb, ARRAY['solidity','base','l2','react','consumer']::text[]),
  ('ethindia-cdp-sdk', 'Coinbase Developer Platform — Most Innovative Use of CDP SDK', 'ETHIndia 2024 sponsor track with a 7,500 USD top bounty for projects built on Coinbase Developer Platform''s SDK, covering wallets-as-a-service, onramps, and smart contract APIs. The crypto-x-AI sub-bounty rewards autonomous agent flows.', 'Sign up for a CDP project at portal.cdp.coinbase.com, grab API keys, and install @coinbase/coinbase-sdk in a Node or Python service. Stand up a minimal Express endpoint that mints a server-controlled wallet, funds it from a faucet on base-sepolia, and signs a sample ERC-20 transfer end-to-end.

For the AI angle, plug the CDP SDK into a LangChain or LangGraph agent so an LLM can decide when to transfer, swap, or call a contract — CDP publishes a CDP AgentKit that wraps these primitives as tools. Pick a narrow scenario like an autonomous prediction-market bettor, a payroll splitter, or a subscription cancellator, and demo the entire loop from natural-language prompt to onchain transaction.', 'Web3', 'intermediate', 'Coinbase', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"CDP docs","url":"https://docs.cdp.coinbase.com/","kind":"docs"},{"label":"AgentKit repo","url":"https://github.com/coinbase/agentkit","kind":"repo"}]'::jsonb, ARRAY['typescript','python','cdp','ai-agents','web3']::text[]),
  ('ethindia-anon-aadhaar', 'Privacy + Scaling Explorations — Best Use of Anon Aadhaar', 'PSE''s ETHIndia 2024 bounty of 3,500 USD for apps that prove Indian identity onchain without revealing personal data, using zero-knowledge proofs over the signed Aadhaar QR code. Anchored the event''s quadratic-voting matching pool.', 'Read the Anon Aadhaar protocol paper, then clone anon-aadhaar/anon-aadhaar and run the provided React example locally to generate your first proof from a personal Aadhaar offline KYC PDF. The proof attests citizenship, age bucket, or state without leaking the 12-digit number.

Design a product where a person-binding assertion unlocks something — examples PSE highlighted are sybil-resistant airdrops, Indian-only DAOs, location-restricted polls, and youth-only safe spaces. Wire the verifier contract on a testnet such as Sepolia, integrate the React prover, and add a graceful fallback for users without a recent Aadhaar PDF.', 'Web3', 'advanced', 'Ethereum Foundation PSE', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"Anon Aadhaar docs","url":"https://documentation.anon-aadhaar.pse.dev/","kind":"docs"},{"label":"Anon Aadhaar repo","url":"https://github.com/anon-aadhaar/anon-aadhaar","kind":"repo"}]'::jsonb, ARRAY['zk','identity','aadhaar','solidity','react']::text[]),
  ('ethindia-huddle01-ai-track', 'Huddle01 — AI Track', 'ETHIndia 2024 sponsor track from Huddle01 (decentralised real-time comms) offering 2,500 USD for the best AI-powered video or audio experience built on their SDK. Think transcription bots, conversational agents, or AI cohosts that join live meetings.', 'Create a Huddle01 project at huddle01.com, install @huddle01/react and the matching server SDK, and run their Next.js starter to verify you can host a peer-to-peer room locally. Confirm raw audio frames are reachable through the data channel API — this is what you will feed to the AI pipeline.

Pipe the live media through Whisper for transcription and stream the result into an LLM that produces meeting actions, follow-up emails, or live captioning. A polished demo joins as a synthetic participant, listens, and posts a summary back into the room — record a 90-second clip showing the bot reacting in real time.', 'Web3', 'intermediate', 'Huddle01', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"Huddle01 docs","url":"https://docs.huddle01.com/","kind":"docs"}]'::jsonb, ARRAY['webrtc','ai','whisper','react','real-time']::text[]),
  ('ethindia-citrea-bitcoin', 'Citrea — Best Use of BitcoinLightClient', 'ETHIndia 2024 bounty of 2,000 USD from Citrea, the first zk rollup for Bitcoin. Teams build dapps that read Bitcoin state from inside an EVM contract using Citrea''s BitcoinLightClient precompile.', 'Spin up the Citrea devnet locally with their docker-compose file from docs.citrea.xyz, then deploy a Hardhat sample that calls the BitcoinLightClient precompile to verify a real mainnet Bitcoin transaction inclusion proof. Get a green test before touching product code.

Design a feature only possible when EVM contracts can trustlessly read Bitcoin — examples are BTC-backed stablecoins, ordinal-gated communities, or DeFi vaults that auto-liquidate when an attacker''s BTC moves. Ship a small frontend that watches a Bitcoin address and reacts on Citrea, and explain in your README why it could not be done on plain Ethereum.', 'Web3', 'advanced', 'Citrea', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"Citrea docs","url":"https://docs.citrea.xyz/","kind":"docs"}]'::jsonb, ARRAY['bitcoin','zk-rollup','solidity','defi']::text[]),
  ('ethindia-okto-consumer', 'Okto by CoinDCX — Best Consumer-Focused Application Using Okto', 'Okto''s flagship ETHIndia 2024 prize of 5,000 USD for consumer dapps built on its multi-chain orchestration layer — gas abstraction, intent-based transactions, and a single embedded wallet across many chains.', 'Register for an Okto API key, install @okto_web3/react-sdk, and run their starter to log in with Google and mint an embedded multi-chain wallet on the spot. Verify you can fire a cross-chain swap intent from the SDK without the user ever signing a raw transaction.

Focus on a consumer flow where Web3 normally breaks down — onboarding a non-crypto-native user, paying a creator across chains, or sending an in-game reward. Build a mobile-first PWA, hide every blockchain word from the UI, and prove a non-technical friend can complete the core action in under 30 seconds on first install.', 'Web3', 'intermediate', 'Okto / CoinDCX', 'Devfolio', 'ETHIndia 2024', 'https://ethindia2024.devfolio.co/prizes', '[]'::jsonb, '[{"label":"Okto docs","url":"https://docs.okto.tech/","kind":"docs"}]'::jsonb, ARRAY['react','multichain','wallets','consumer','abstraction']::text[]),
  ('mlh-best-use-of-gemini-api', 'MLH — Best Use of Gemini API', 'MLH 2024 season prize from Google rewarding AI apps built on the Gemini API. Winning hacks tend to combine Gemini''s multimodal vision and long-context features with a sharp end-user product, not just a chat wrapper.', 'Grab a free Gemini API key at aistudio.google.com, install @google/generative-ai for JS or google-generativeai for Python, and get a multimodal call working locally that takes an image plus a question and returns structured JSON. Lock in JSON-mode early — judges hate flaky parsing.

Differentiate by attacking a workflow that needs vision plus reasoning — receipt-to-budget, lab-notebook-to-LaTeX, whiteboard-to-Figma, or video-to-study-guide. Use Gemini''s long-context window to skip embeddings for short corpuses, and back the UI with a thin Next.js or Streamlit shell so the demo is fast and shareable.', 'AI/ML', 'beginner', 'Google', 'MLH', 'MLH 2024 Season', 'https://www.mlh.com/events/prizes', '[]'::jsonb, '[{"label":"Gemini API docs","url":"https://ai.google.dev/gemini-api/docs","kind":"docs"},{"label":"Google AI Studio","url":"https://aistudio.google.com/","kind":"tutorial"}]'::jsonb, ARRAY['gemini','google','ai','multimodal','javascript']::text[]),
  ('mlh-elevenlabs-voice', 'MLH — Best Use of ElevenLabs', 'ElevenLabs sponsor challenge across the MLH 2024 season for hacks that put expressive AI voice front-and-centre — voice agents, dubbing, accessibility, or interactive audio narratives. Prize is a set of wireless earbuds per team member.', 'Create an ElevenLabs account, copy the API key, and call the text-to-speech endpoint with the elevenlabs-python SDK to confirm latency and voice options. Try the new low-latency streaming endpoint and the Conversational AI agents builder — both unlock interactive use cases.

Good directions are voice-first companions for people with disabilities, real-time language dubbing for video calls, audio learning tools, or game NPCs with consistent voice identity. Pair ElevenLabs with Whisper for the input side and an LLM for reasoning, and showcase a clip where a user converses naturally with your app for at least 30 seconds.', 'AI/ML', 'beginner', 'ElevenLabs', 'MLH', 'MLH 2024 Season', 'https://www.mlh.com/events/prizes', '[]'::jsonb, '[{"label":"ElevenLabs docs","url":"https://elevenlabs.io/docs","kind":"docs"}]'::jsonb, ARRAY['voice','tts','ai','python','accessibility']::text[]),
  ('mlh-auth0-ai-agents', 'MLH — Best Use of Auth0 AI Agents', 'Auth0 sponsor track at MLH 2024 for projects that secure agent-to-user and agent-to-agent interactions using Auth0''s new AI Agents toolkit — delegation, consent, and fine-grained authorization for autonomous LLM workflows.', 'Spin up a free Auth0 tenant, enable the AI Agents preview, and run the official Auth0 AI sample with LangChain or LlamaIndex. The sample wires up token-bound calls so an agent can act on a user''s behalf without holding raw credentials — confirm a tool call goes through end-to-end before designing further.

Pick a use case where agents must touch sensitive data — a personal finance copilot, an inbox triager, a calendar negotiator. Use Auth0''s CIBA flow for asynchronous human approval, and demonstrate the agent gracefully blocking and waiting when consent is revoked mid-task. That security narrative is what wins this prize.', 'AI/ML', 'intermediate', 'Auth0', 'MLH', 'MLH 2024 Season', 'https://www.mlh.com/events/prizes', '[]'::jsonb, '[{"label":"Auth0 AI docs","url":"https://auth0.com/ai","kind":"docs"}]'::jsonb, ARRAY['auth0','ai-agents','security','oauth','langchain']::text[]),
  ('mlh-cloudflare-workers-ai', 'MLH — Best AI Application Built with Cloudflare', 'Cloudflare''s MLH 2024 prize for full-stack AI apps deployed on Cloudflare Workers AI, Vectorize, and R2. Rewards apps that serve real users at the edge instead of long-running boxes.', 'Install wrangler, run npm create cloudflare to scaffold a Workers AI template, and pick a model from the Workers AI catalogue such as Llama 3 or BGE embeddings. Confirm a hello-world inference call returns from the edge in under a second.

Build a RAG product end-to-end on Cloudflare primitives — D1 for metadata, R2 for documents, Vectorize for embeddings, and Workers AI for both embedding and generation. Demonstrate edge benefits explicitly: zero cold starts, global presence, and pay-per-request economics. A focused niche such as a podcast Q&A bot or a textbook tutor reads better than a generic chatbot.', 'AI/ML', 'intermediate', 'Cloudflare', 'MLH', 'MLH 2024 Season', 'https://www.mlh.com/events/prizes', '[]'::jsonb, '[{"label":"Workers AI docs","url":"https://developers.cloudflare.com/workers-ai/","kind":"docs"}]'::jsonb, ARRAY['cloudflare','edge','rag','workers','ai']::text[]),
  ('mlh-snowflake-api', 'MLH — Best Use of Snowflake API', 'Snowflake''s MLH 2024 challenge for hacks that use the Snowflake REST API to bring in-warehouse LLMs and Cortex search into applications. Winner gets a Raspberry Pi 4 per team member.', 'Get a 30-day Snowflake trial, enable Cortex in the trial account, and run the snowflake-snowpark-python or snowflake-connector-python SDK to call Cortex.Complete against a sample model from a notebook. Verify you can query a small text dataset with Cortex.Search as well.

Pick a data-grounded use case where the answer comes from rows you already store — sales coaching, support-ticket triage, compliance Q&A. Build the front end in Streamlit (it has native Snowflake auth), and emphasise that all the AI lives next to the data so no row ever leaves the warehouse. That story aligns with Snowflake''s pitch and judges respond to it.', 'AI/ML', 'intermediate', 'Snowflake', 'MLH', 'MLH 2024 Season', 'https://www.mlh.com/events/prizes', '[]'::jsonb, '[{"label":"Snowflake Cortex","url":"https://docs.snowflake.com/en/user-guide/snowflake-cortex/llm-functions","kind":"docs"}]'::jsonb, ARRAY['snowflake','cortex','rag','python','streamlit']::text[]),
  ('mhacks-2024-midnight-zk', 'MHacks 2024 — Best Use of Midnight', 'MHacks 2024 sponsor challenge from Midnight, an IOG data-protection blockchain. Teams build dApps that exchange shielded data with zero-knowledge proofs while staying compliant.', 'Install the Midnight CLI and the Compact language toolchain from docs.midnight.network, then run the bulletin-board tutorial to deploy a shielded contract on the Midnight testnet. Confirm you can compile a Compact circuit and call it from a TypeScript dapp before touching product code.

Ideal use cases involve sensitive data the user does not want public — anonymous tipping, private credentials, regulated marketplaces, dark-pool order books. Keep the user flow simple: connect Lace wallet, submit private input, get a public attestation. Record a clip showing what a normal block explorer can and cannot see — that contrast is the demo.', 'Web3', 'advanced', 'Midnight', 'MLH', 'MHacks 2024', 'https://www.mlh.com/events/mhacks-2024/prizes', '[]'::jsonb, '[{"label":"Midnight docs","url":"https://docs.midnight.network/","kind":"docs"}]'::jsonb, ARRAY['zk','privacy','blockchain','compact','typescript']::text[]),
  ('mhacks-2024-mathworks-matlab', 'MHacks 2024 — Best Use of MATLAB', 'MathWorks sponsor track at MHacks 2024 rewarding the most creative hack built with MATLAB or Simulink — either as the main engine or integrated into another stack via the MATLAB Engine API.', 'Activate a student MATLAB licence through MathWorks (free for hackathons via the MLH portal), and install the toolboxes you need — typically Signal Processing, Deep Learning, or Image Processing. Run a tutorial that loads sample data, trains a small model with the Deep Network Designer, and exports it to ONNX so a Python or web frontend can consume it.

Favour problems where MATLAB''s strengths actually matter — control systems, signal processing, simulation, biomedical analysis. A typical winning shape is a Simulink simulation of a physical system (drone, prosthetic, energy grid) with a thin web dashboard calling MATLAB via the engine API. Emphasise the math; do not bury Simulink behind an HTML demo.', 'Education', 'intermediate', 'MathWorks', 'MLH', 'MHacks 2024', 'https://www.mlh.com/events/mhacks-2024/prizes', '[]'::jsonb, '[{"label":"MATLAB for hackers","url":"https://www.mathworks.com/academia/student-competitions/major-league-hacking.html","kind":"docs"}]'::jsonb, ARRAY['matlab','simulink','signals','control','engineering']::text[]),
  ('mhacks-2024-fidelity-dei', 'MHacks 2024 — Fidelity Best DEI Hack', 'Fidelity''s MHacks 2024 challenge to build forward-thinking financial tech that promotes equality — accessible, sustainable, or inclusive solutions that close gaps for under-served populations.', 'Anchor on a specific underserved group and a concrete money pain — gig-workers without paystubs, first-generation immigrants without credit history, students navigating financial aid, or seniors targeted by scams. Interview at least one person in that group on day one rather than guessing.

Reach for boring stacks that ship — Next.js plus Supabase plus Plaid Sandbox plus a small AI helper. Plaid''s free sandbox simulates bank data without real accounts, which is enough for a hackathon demo. Highlight one measurable equity outcome in your pitch (cost saved, hours saved, error rate dropped) instead of vague aspirations.', 'FinTech', 'intermediate', 'Fidelity', 'MLH', 'MHacks 2024', 'https://www.mlh.com/events/mhacks-2024/prizes', '[]'::jsonb, '[{"label":"Plaid Sandbox","url":"https://plaid.com/docs/sandbox/","kind":"docs"}]'::jsonb, ARRAY['fintech','dei','accessibility','plaid','react']::text[]),
  ('unstop-amazon-ml-challenge', 'Amazon ML Challenge', 'Amazon''s annual machine-learning hackathon on Unstop for Indian engineering students. Past editions ask teams to ship a real ML pipeline against a noisy product-catalogue dataset, with leaderboards and PPI shortlists for top finishers.', 'Form a team of two to four, register on the Unstop event page, and download the train and test CSVs as soon as the dataset drops. Start with a fast baseline — TF-IDF plus LightGBM for tabular, or a frozen transformer plus a linear head for text — and submit something the same day so you sit on the leaderboard from hour zero.

From there, iterate ruthlessly: error analysis on misclassified samples, careful cross-validation that mirrors the leaderboard split, and only then try heavy approaches like fine-tuned RoBERTa or a CLIP image-text model if the data is multimodal. Track every experiment in MLflow or a spreadsheet, and write the inference script for the test set early — many teams lose points to last-minute submission bugs.', 'AI/ML', 'advanced', 'Amazon', 'Unstop', 'Amazon ML Challenge', 'https://unstop.com/hackathons/amazon-ml-challenge-amazon-1100713', '[]'::jsonb, '[{"label":"LightGBM docs","url":"https://lightgbm.readthedocs.io/","kind":"docs"},{"label":"Hugging Face Transformers","url":"https://huggingface.co/docs/transformers/index","kind":"docs"}]'::jsonb, ARRAY['python','ml','amazon','competition','kaggle-style']::text[]),
  ('unstop-hackon-amazon', 'HackOn with Amazon', 'Amazon India''s flagship Unstop hackathon for engineering students — multi-round, with a coding screen, an idea round, and a 48-hour build phase where shortlisted teams ship a working prototype against a kickoff-day problem statement. Top finishers get PPI shortlists.', 'Treat the qualifier coding round seriously — it is a HackerRank-style DSA test, and the bar is real placement-prep difficulty. Drill the standard Striver or Neetcode 150 list in the weeks leading up to it, and practise medium-hard arrays, graphs, and DP problems under time pressure.

For the build phase, the problem statement is shared only at the kickoff webinar, so prepare a reusable starter — a Next.js plus FastAPI plus Postgres scaffold with auth, deploy scripts, and a logger already wired up. Recent editions lean heavily into GenAI, so pre-stage a Bedrock or OpenAI key and a vector store. Submit a clean GitHub repo, a five-minute demo video, and a sharp PPT — many strong builds lose because of weak presentation.', 'Web', 'advanced', 'Amazon', 'Unstop', 'HackOn with Amazon', 'https://unstop.com/blog/hackon-with-amazon', '[]'::jsonb, '[{"label":"AWS Bedrock","url":"https://aws.amazon.com/bedrock/","kind":"docs"}]'::jsonb, ARRAY['amazon','fullstack','genai','placement','india']::text[]),
  ('unstop-adobe-india-hackathon', 'Adobe India Hackathon — Rethink Reading, Rediscover Knowledge', 'Adobe''s flagship Unstop hackathon themed around reimagining PDFs as intelligent, interactive experiences. Teams build the core system that powers document understanding and semantic linking against Adobe''s brief.', 'Start by reverse-engineering the public PDFs you read every week — what would make a textbook, a legal contract, or a research paper actually queryable. Build a parser pipeline using PyMuPDF or pdfplumber for layout, a vision model such as Donut or LayoutLMv3 for figures and tables, and an embedding model for semantic search.

The winning shape is an end-to-end reader app — upload PDF, get an outline, ask a question, get an answer grounded with page citations and inline highlights. Use the Adobe PDF Embed API for the viewer because Adobe judges notice when you use their primitives. Ship it as a deployable web app, not a notebook, and benchmark answer quality on at least 20 hand-labelled questions before submission.', 'AI/ML', 'advanced', 'Adobe', 'Unstop', 'Adobe India Hackathon 2025', 'https://unstop.com/hackathons/adobe-india-hackathon-adobe-1483364', '[]'::jsonb, '[{"label":"Adobe PDF Embed API","url":"https://developer.adobe.com/document-services/apis/pdf-embed/","kind":"docs"},{"label":"PyMuPDF docs","url":"https://pymupdf.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['adobe','pdf','rag','python','document-ai']::text[]),
  ('unstop-canara-suraksha-cyber', 'SuRaksha Cyber Hackathon — Canara Bank', 'Canara Bank''s cybersecurity hackathon hosted on HackerEarth (cross-promoted on Unstop) for Indian undergraduates. Themes orbit banking fraud detection, secure customer onboarding, and threat-intelligence tooling.', 'Pick a single banking threat surface to attack — UPI fraud rings, deepfake video-KYC bypass, synthetic-identity loan applications, or phishing-site detection. Each maps to a well-defined ML or systems problem with a clean demo.

Use public datasets to bootstrap — IEEE-CIS Fraud, PaySim, or the synthetic UPI logs published in NPCI hackathons — and ship a real-time scoring service on FastAPI plus a small React dashboard for the SOC analyst. Demonstrate the system catching an attack on a recorded video, and document the false-positive rate honestly, since banks care more about precision than flashy ML.', 'FinTech', 'intermediate', 'Canara Bank', 'Unstop', 'SuRaksha Cyber Hackathon', 'https://canarabank.hackerearth.com/', '[{"label":"IEEE-CIS Fraud","url":"https://www.kaggle.com/competitions/ieee-fraud-detection/data","format":"csv"}]'::jsonb, '[{"label":"FastAPI docs","url":"https://fastapi.tiangolo.com/","kind":"docs"}]'::jsonb, ARRAY['cybersecurity','fintech','fraud','banking','python']::text[]),
  ('os-build-your-own-shell', 'Build Your Own Shell', 'Evergreen Coding Challenges project to implement a Unix-style command-line shell — parsing, builtins, pipes, redirection, and job control — strong enough to run a small set of real scripts.', 'Start in your favourite systems-friendly language (Go, Rust, or C are ideal) and write a REPL that reads a line, splits it on whitespace, and forks-execs the command. Get cd, pwd, and exit working as builtins before anything else, then add PATH lookup.

Layer features one at a time — single pipes via pipe and fork, then arbitrary-length pipelines, then input and output redirection with dup2, then environment variable expansion, then a job table for background processes and Ctrl-Z. Stop once your shell can run a small bash script for setting up a project — the goal is depth of understanding, not feature creep.', 'OpenSource', 'intermediate', 'Self-directed', 'OpenSource', NULL, 'https://codingchallenges.fyi/challenges/intro/', '[]'::jsonb, '[{"label":"Shell in C tutorial","url":"https://brennan.io/2015/01/16/write-a-shell-in-c/","kind":"tutorial"}]'::jsonb, ARRAY['c','go','rust','unix','systems']::text[]),
  ('os-build-your-own-http-load-balancer', 'Build Your Own HTTP Load Balancer', 'Coding Challenges project that asks you to ship a working layer-7 load balancer — round-robin scheduling, health checks, sticky sessions, and graceful backend draining. A great hands-on intro to reverse proxies and concurrency primitives.', 'Stand up two or three trivial HTTP backends on different ports (each can be a 30-line Go or Node service that returns its hostname) and confirm they answer with curl. Then write a single-threaded proxy that round-robins requests across them — net/http in Go or asyncio in Python is enough to start.

Add a periodic health-check goroutine or task that GETs /health and removes unhealthy backends from the pool. Then introduce concurrency, sticky sessions via a hash on the source IP, weighted round-robin, and finally graceful drain so a backend stops receiving new traffic before shutting down. Benchmark with wrk and document the throughput before and after each change.', 'OpenSource', 'intermediate', 'Self-directed', 'OpenSource', NULL, 'https://codingchallenges.fyi/challenges/challenge-load-balancer', '[]'::jsonb, '[{"label":"wrk benchmarking","url":"https://github.com/wg/wrk","kind":"repo"}]'::jsonb, ARRAY['go','networking','proxy','concurrency','systems']::text[]),
  ('os-build-your-own-rate-limiter', 'Build Your Own Rate Limiter', 'Coding Challenges project to implement a production-style rate limiter — token bucket, leaky bucket, fixed-window, and sliding-window — both as a library and as middleware sitting in front of a real HTTP service.', 'Pick a language with first-class concurrency such as Go or Rust, and write a token-bucket struct that supports allow(key) with configurable rate and burst. Wrap it in Go''s chi middleware or Rust''s tower layer and stick it in front of a sample echo server.

Move to a distributed setting by backing the buckets with Redis and using INCR plus EXPIRE with millisecond precision for the fixed-window algorithm. Implement the sliding-window log and the sliding-window counter variants, then benchmark each under hey or k6 — show the trade-offs in accuracy and memory in a README table. That comparative analysis is the deliverable that makes this project stand out on a resume.', 'OpenSource', 'intermediate', 'Self-directed', 'OpenSource', NULL, 'https://codingchallenges.fyi/challenges/challenge-rate-limiter', '[]'::jsonb, '[{"label":"Stripe rate limiting blog","url":"https://stripe.com/blog/rate-limiters","kind":"tutorial"}]'::jsonb, ARRAY['go','rust','redis','distributed-systems','middleware']::text[]),
  ('os-build-your-own-json-parser', 'Build Your Own JSON Parser', 'Classic Coding Challenges project — implement a JSON parser from the spec including the conformance test suite. Strengthens lexing, recursive descent parsing, and Unicode handling without an enormous time commitment.', 'Read RFC 8259 cover to cover once — it is short. Then sketch a tokeniser that classifies characters into LBRACE, RBRACE, COMMA, STRING, NUMBER, TRUE, FALSE, NULL, and EOF. Write a unit test per token type before parsing anything.

Move to a recursive-descent parser with one function per non-terminal — parseValue dispatches into parseObject, parseArray, parseString, or parseNumber. Run the official JSONTestSuite from nst/JSONTestSuite as your CI — it catches the gnarly edge cases (lone surrogates, trailing commas, deeply nested arrays) you would otherwise ship broken.', 'OpenSource', 'beginner', 'Self-directed', 'OpenSource', NULL, 'https://codingchallenges.fyi/challenges/challenge-json-parser', '[]'::jsonb, '[{"label":"JSONTestSuite","url":"https://github.com/nst/JSONTestSuite","kind":"repo"},{"label":"RFC 8259","url":"https://datatracker.ietf.org/doc/html/rfc8259","kind":"docs"}]'::jsonb, ARRAY['parsing','compilers','any-language','fundamentals']::text[]),
  ('os-build-your-own-dns-resolver', 'Build Your Own DNS Resolver', 'Coding Challenges project to write a recursive DNS resolver — encode and decode the wire format from scratch and walk the delegation chain from the root servers down to the answer. No external DNS libraries allowed.', 'Read RFC 1035 sections 3 and 4 to understand the wire format — header, question, answer, authority, and additional sections, plus the wonderfully tricky name-compression scheme. Open a UDP socket to 198.41.0.4 (a root server) and hand-craft a query for the A record of example.com.

Write the decoder before the resolver loop. Once you can parse responses, implement the recursive walk: query a root, follow the NS records to the TLD server, follow those to the authoritative, and finally to the answer. Add a small LRU cache respecting TTLs, then implement DNS-over-HTTPS as a stretch goal using Cloudflare''s 1.1.1.1 endpoint.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://codingchallenges.fyi/challenges/challenge-dns-resolver', '[]'::jsonb, '[{"label":"Implement DNS in a Weekend","url":"https://implement-dns.wizardzines.com/","kind":"tutorial"},{"label":"RFC 1035","url":"https://datatracker.ietf.org/doc/html/rfc1035","kind":"docs"}]'::jsonb, ARRAY['networking','dns','python','go','systems']::text[]),
  ('os-build-your-own-git', 'Build Your Own Git', 'Classic build-your-own-x project to implement the plumbing of Git — blobs, trees, commits, refs, the index, and basic push and pull over the smart HTTP protocol. The CodeCrafters and the Wyag tutorials are both excellent companions.', 'Read the first three chapters of the Pro Git book to internalise the object model — then ignore everything about porcelain commands and focus only on plumbing. Implement git hash-object and git cat-file first; you cannot do anything else without these.

Build up the index, the tree, and the commit object in that order, each backed by content-addressed storage under .git/objects. Then add refs and HEAD, then a real working tree update for git checkout. Finally implement the smart HTTP transfer protocol so your tool can push to a real GitHub repo — that final integration is the moment everything clicks.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://wyag.thb.lt/', '[]'::jsonb, '[{"label":"Write yourself a Git","url":"https://wyag.thb.lt/","kind":"tutorial"},{"label":"CodeCrafters Git","url":"https://app.codecrafters.io/courses/git/overview","kind":"tutorial"}]'::jsonb, ARRAY['git','python','go','systems','vcs']::text[]),
  ('os-build-your-own-sqlite', 'Build Your Own SQLite', 'CodeCrafters project to implement a barebones SQLite that can run real SELECT queries against a real .db file. Teaches the SQLite file format, B-tree page layout, varints, and basic SQL parsing.', 'Read the SQLite file format spec at sqlite.org/fileformat.html — it is the source of truth and shorter than you would think. Open a real sample.db with a hex editor in parallel; pattern-matching bytes to spec sections is the fastest learning loop.

Implement reading in stages — header, schema table, B-tree pages for tables, then indexes. Add a tiny SQL parser using a hand-rolled recursive descent — you only need SELECT, FROM, WHERE, and a couple of operators to clear the challenge. Stop short of writes; reading is already a substantial systems project.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://app.codecrafters.io/courses/sqlite/overview', '[]'::jsonb, '[{"label":"SQLite file format","url":"https://www.sqlite.org/fileformat.html","kind":"docs"}]'::jsonb, ARRAY['database','btree','sql','rust','go']::text[]),
  ('os-build-your-own-kafka', 'Build Your Own Kafka', 'CodeCrafters challenge to implement a Kafka broker that speaks the real Kafka wire protocol — bind a TCP port, parse correlation IDs and API versions, handle Produce and Fetch, and serve multiple clients concurrently.', 'Read Apache Kafka''s protocol guide at kafka.apache.org/protocol — concentrate on the request header format and the ApiVersions, Produce, and Fetch APIs. The wire protocol uses length-prefixed framing and a small bestiary of primitive types; write the codec module before touching any business logic.

Get a basic TCP listener echoing correlation IDs back, then implement ApiVersions so the official Kafka CLI client can connect. Add an in-memory log per topic-partition, implement Produce, then Fetch with offset support. Run the kafka-console-producer and consumer against your broker as the integration test — there is no better validation.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://app.codecrafters.io/courses/kafka/overview', '[]'::jsonb, '[{"label":"Kafka protocol","url":"https://kafka.apache.org/protocol","kind":"docs"}]'::jsonb, ARRAY['kafka','distributed-systems','go','rust','networking']::text[]),
  ('os-build-your-own-bittorrent', 'Build Your Own BitTorrent Client', 'CodeCrafters and build-your-own-x staple — implement the BitTorrent peer protocol, parse .torrent bencode, talk to a tracker, and download a real file from real peers. Wonderful exposure to peer-to-peer networking and binary protocols.', 'Start with a bencode decoder and the .torrent parser; you should be able to print announce URL, piece length, info hash, and piece hashes from a real torrent before any networking. Pick a small legal torrent (the Debian net-install ISO is the classic) to test against.

Next talk to the tracker over HTTP, parse the compact peer list, and open a TCP connection to one peer. Send the BitTorrent handshake, then exchange bitfields, then request and verify pieces against their SHA-1 hashes. Once a single-peer download works, add a piece-picker and parallel connections — that is where the real engineering lives.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://app.codecrafters.io/courses/bittorrent/overview', '[]'::jsonb, '[{"label":"Kristen Widman BitTorrent series","url":"https://blog.jse.li/posts/torrent/","kind":"tutorial"}]'::jsonb, ARRAY['p2p','networking','go','rust','binary-protocols']::text[]),
  ('os-crafting-interpreters-lox', 'Crafting Interpreters — Build the Lox Language', 'Bob Nystrom''s free book guides you from zero to a tree-walking interpreter (jlox in Java) and then a bytecode VM with a single-pass compiler and garbage collector (clox in C). The benchmark text for anyone implementing a programming language.', 'Read the book front-to-back in browser or PDF before writing code — Nystrom''s narrative is the value, not just the code. Then implement jlox chapter by chapter, typing the code yourself rather than copy-pasting. Push to a public repo with one commit per chapter so you can show your progress.

Once jlox runs the full Lox feature set including closures and classes, switch languages — write clox in C exactly as the book teaches, including the hand-rolled hash table, the Pratt parser, the stack-based VM, and the mark-sweep collector. Extending the language afterwards (adding lists, modules, or a JIT) is the natural follow-up that makes this project distinctive on a CV.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://craftinginterpreters.com/', '[]'::jsonb, '[{"label":"Crafting Interpreters source","url":"https://github.com/munificent/craftinginterpreters","kind":"repo"}]'::jsonb, ARRAY['compilers','interpreters','java','c','languages']::text[]),
  ('os-build-your-own-text-editor-kilo', 'Build Your Own Text Editor (Kilo Tutorial)', 'Build a syntax-highlighting modal text editor in under 1000 lines of C, following the Snaptoken Kilo tutorial. Teaches raw terminal mode, escape sequences, incremental file I/O, and search — without ncurses.', 'Open a fresh C project and follow Snaptoken''s Build Your Own Text Editor chapters in order — they are tiny, around 100 to 200 lines per step, and the diffs are shown inline. Resist the urge to refactor early; each chapter introduces a concept that depends on the previous structure.

Once Kilo is feature-complete (open, edit, save, search, syntax highlight), extend it. Good extensions are vim-style modal editing, line numbers, mouse support, or a tiny scripting hook in Lua. The pleasure here is that every keystroke in your editor is code you wrote — that visceral feeling is exactly what to communicate in your README.', 'OpenSource', 'intermediate', 'Self-directed', 'OpenSource', NULL, 'https://viewsourcecode.org/snaptoken/kilo/', '[]'::jsonb, '[{"label":"Kilo source","url":"https://github.com/antirez/kilo","kind":"repo"}]'::jsonb, ARRAY['c','terminal','editors','systems']::text[]),
  ('os-build-your-own-docker', 'Build Your Own Docker', 'Build-your-own-x project to implement a minimal Linux container runtime — namespaces, cgroups, overlay filesystems, and a tiny pull-and-run flow for real OCI images. Lifts the lid on what docker run actually does.', 'Set up a Linux VM (Ubuntu in WSL2 or a small cloud box) since the kernel features are Linux-only. Write a Go or Rust program that calls clone with CLONE_NEWUTS, CLONE_NEWPID, CLONE_NEWNS, and CLONE_NEWNET, execs /bin/sh inside, and confirms with hostname and ps that the child is isolated.

Add a chroot with a real Alpine rootfs you extracted from a pulled OCI image (use crane or skopeo to fetch). Then bring in cgroups v2 to cap CPU and memory, an overlayfs to give the container a writable layer, and a veth pair plus a bridge for networking. Read Liz Rice''s Containers From Scratch talk alongside — it remains the clearest mental model.', 'OpenSource', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://github.com/codecrafters-io/build-your-own-x', '[]'::jsonb, '[{"label":"Containers from Scratch (Liz Rice)","url":"https://www.youtube.com/watch?v=8fi7uSYlOdc","kind":"tutorial"}]'::jsonb, ARRAY['containers','linux','go','systems','kernel']::text[]),
  ('os-build-your-own-search-engine', 'Build Your Own Search Engine', 'Implement a small but full search engine from scratch — crawler, tokeniser, inverted index, BM25 ranking, and a query frontend over your favourite document corpus. A great way to internalise information retrieval and to build a portfolio piece more interesting than another CRUD app.', 'Pick a bounded corpus first — Wikipedia simple-English, your personal Obsidian vault, or the Stack Exchange dump. Build a tokeniser in Python or Rust, write the inverted index to a flat file or to SQLite, and implement BM25 scoring from the Manning IR textbook formula. Verify on a handful of queries by hand.

Graduate to a crawler that respects robots.txt, deduplicates URLs, and stores raw HTML on disk. Add a small frontend (htmx plus FastAPI is enough) with query autocomplete via a prefix trie, snippet highlighting, and pagination. Optional last step: pipe the top results through a small reranker model from sentence-transformers and compare nDCG before and after — that proper evaluation is what makes the project read as serious.', 'AI/ML', 'advanced', 'Self-directed', 'OpenSource', NULL, 'https://nlp.stanford.edu/IR-book/information-retrieval-book.html', '[{"label":"Wikipedia dumps","url":"https://dumps.wikimedia.org/","format":"json"}]'::jsonb, '[{"label":"Stanford IR Book (free)","url":"https://nlp.stanford.edu/IR-book/","kind":"docs"}]'::jsonb, ARRAY['search','ir','bm25','python','rust']::text[])
ON CONFLICT (slug) DO NOTHING;

